WEB_RECALL_ENABLED = os.getenv("WEB_RECALL_ENABLED", "1").strip().lower() in ("1", "true", "yes", "y")
WEB_RECALL_QUERY_CAP_PER_SECTION = int(os.getenv("WEB_RECALL_QUERY_CAP_PER_SECTION", "2") or 2)
