# 1페이지 결과가 꽉 찬(=50건) 쿼리는 2페이지에 유의미한 '윈도우 내' 기사가 남아 있을 가능성이 높다.
# 후보 풀이 부족할 때만, 상위 N개 쿼리에 대해 page2를 우선적으로 시도한다.
RECALL_HIGH_VOLUME_PAGE2_QUERIES = int(os.getenv("RECALL_HIGH_VOLUME_PAGE2_QUERIES", "2") or 2)
