# 섹션 배치 안정화: 최종 선발/전역 재분류 시 section-fit 신호를 함께 본다.
SECTION_FIT_MIN_FOR_TOP = float(os.getenv("SECTION_FIT_MIN_FOR_TOP", "0.8") or 0.8)
SECTION_FIT_MIN_FOR_TOP = max(0.0, min(SECTION_FIT_MIN_FOR_TOP, 5.0))
