# -----------------------------
NAVER_MIN_INTERVAL_SEC = float(os.getenv("NAVER_MIN_INTERVAL_SEC", "0.35"))  # 최소 호출 간격(초)
NAVER_MAX_RETRIES = int(os.getenv("NAVER_MAX_RETRIES", "6"))
