# -----------------------------
# Data model
# -----------------------------
@dataclass
class Article:
    section: str
    title: str
    description: str
    link: str
    originallink: str
    pub_dt_kst: datetime
    domain: str
    press: str
    norm_key: str
    title_key: str
    canon_url: str
    topic: str
    is_core: bool = False
    score: float = 0.0
    summary: str = ""
    forced_section: str = ""
    origin_section: str = ""
    source_query: str = ""
    source_channel: str = ""
    selection_stage: str = ""
    selection_note: str = ""
    selection_fit_score: float = 0.0
    reassigned_from: str = ""
    semantic_similarity: float = 0.0
    semantic_noise_similarity: float = 0.0
    semantic_margin: float = 0.0
    semantic_boost: float = 0.0
    semantic_model: str = ""

    @property
    def url(self) -> str:
        return self.originallink or self.link or self.canon_url


_LAST_COMMODITY_BOARD_SOURCE_BY_SECTION: dict[str, list["Article"]] = {}


def _set_last_commodity_board_source(source: dict[str, list["Article"]] | None) -> None:
    global _LAST_COMMODITY_BOARD_SOURCE_BY_SECTION
    data: dict[str, list["Article"]] = {}
    for sec in SECTIONS:
        key = str(sec.get("key") or "").strip()
        if not key:
            continue
        items = []
        for article in (source or {}).get(key, []) or []:
            if isinstance(article, Article):
                items.append(article)
        data[key] = items
    _LAST_COMMODITY_BOARD_SOURCE_BY_SECTION = data


def _get_last_commodity_board_source() -> dict[str, list["Article"]]:
    data = _LAST_COMMODITY_BOARD_SOURCE_BY_SECTION or {}
    return {
        str(sec.get("key") or "").strip(): list(data.get(str(sec.get("key") or "").strip(), []) or [])
        for sec in SECTIONS
        if str(sec.get("key") or "").strip()
    }


def _merge_commodity_board_source_with_final_selection(
    final_by_section: dict[str, list["Article"]] | None,
    source_by_section: dict[str, list["Article"]] | None,
) -> dict[str, list["Article"]]:
    """Keep every final briefing card in the commodity-board source pool."""
    merged: dict[str, list["Article"]] = {}
    final_data = final_by_section if isinstance(final_by_section, dict) else {}
    source_data = source_by_section if isinstance(source_by_section, dict) else {}
    for sec in SECTIONS:
        section_key = str(sec.get("key") or "").strip()
        if not section_key:
            continue
        picked: list[Article] = []
        seen: set[str] = set()
        # Final briefing cards come first so a selected/reassigned instance wins
        # over an older raw-pool copy with the same URL.
        for article in list(final_data.get(section_key, []) or []) + list(source_data.get(section_key, []) or []):
            if not isinstance(article, Article):
                continue
            ident = _article_selection_identity(article)
            if ident and ident in seen:
                continue
            if ident:
                seen.add(ident)
            picked.append(article)
        merged[section_key] = picked
    return merged


def build_managed_commodity_board_source_by_section(
    by_section: dict[str, list["Article"]],
    per_section_cap: int | None = None,
) -> dict[str, list["Article"]]:
    cap = max(24, int(per_section_cap or max(MAX_PER_SECTION * 18, 120)))
    out: dict[str, list["Article"]] = {}
    for sec in SECTIONS:
        section_key = str(sec.get("key") or "").strip()
        eligible_records: list[tuple[Article, list[tuple[str, dict[str, Any]]]]] = []
        distinct_sources: set[str] = set()
        for article in sorted(by_section.get(section_key, []) or [], key=_sort_key_major_first, reverse=True):
            if not isinstance(article, Article):
                continue
            board_keys = managed_commodity_board_keys_for_article(article)
            if not board_keys:
                continue
            reject_reason = _postbuild_article_reject_reason(article, section_key, apply_selection_fit=False)
            if reject_reason and not (
                section_key == "dist"
                and reject_reason == "dist_primary_supply_price_story"
            ):
                continue
            strict_records: list[tuple[str, dict[str, Any]]] = []
            title_l = _nfkc_lower(getattr(article, "title", "") or "")
            if _commodity_board_title_issue_hits(title_l) > 0:
                for key in board_keys[:2]:
                    item = MANAGED_COMMODITY_BY_KEY.get(str(key) or "")
                    if not item:
                        continue
                    # Active primary requires a direct title item hit. Check that cheap
                    # gate before the heavier representative metrics pass.
                    if _commodity_board_term_hits(title_l, _managed_commodity_base_terms(item, limit=6)) <= 0:
                        continue
                    metrics = _commodity_board_item_article_representative_metrics(
                        item,
                        article,
                        include_semantic=False,
                    )
                    if _commodity_board_article_is_active_candidate(item, article, metrics):
                        strict_records.append((str(key), dict(metrics)))
            eligible_records.append((article, strict_records))
            source_key = article_source_bucket_key(article)
            if source_key:
                distinct_sources.add(source_key)

        per_source_cap = cap
        if len(distinct_sources) >= 6:
            per_source_cap = 2
        elif len(distinct_sources) >= 3:
            per_source_cap = 3

        picked: list[Article] = []
        seen_keys: set[str] = set()
        source_counts: dict[str, int] = {}
        best_strict_by_item: dict[str, tuple[tuple[Any, ...], Article]] = {}
        for article, strict_records in eligible_records:
            for item_key, metrics in strict_records:
                sort_key = (
                    int(metrics.get("representative_rank", -1)),
                    float(metrics.get("representative_score", 0.0) or 0.0),
                    float(metrics.get("board_score", 0.0) or 0.0),
                    float(metrics.get("story_priority", 0.0) or 0.0),
                    *_sort_key_major_first(article),
                )
                current = best_strict_by_item.get(item_key)
                if current is None or sort_key > current[0]:
                    best_strict_by_item[item_key] = (sort_key, article)

        def _add_board_source_article(article: Article, *, enforce_source_cap: bool) -> bool:
            dedupe_key = article.canon_url or article.norm_key or article.title_key or article.url
            if not dedupe_key or dedupe_key in seen_keys:
                return False
            source_key = article_source_bucket_key(article)
            if enforce_source_cap and source_key and per_source_cap < cap and source_counts.get(source_key, 0) >= per_source_cap:
                return False
            seen_keys.add(dedupe_key)
            picked.append(article)
            if source_key:
                source_counts[source_key] = source_counts.get(source_key, 0) + 1
            return True

        strict_reserved = sorted(best_strict_by_item.values(), key=lambda item: item[0], reverse=True)
        for _sort_key, article in strict_reserved:
            _add_board_source_article(article, enforce_source_cap=False)
            if len(picked) >= cap:
                break

        for article, _strict_records in eligible_records:
            if len(picked) >= cap:
                break
            _add_board_source_article(article, enforce_source_cap=True)
        out[section_key] = picked
    return out


# -----------------------------
# Utilities
# -----------------------------
def now_kst() -> datetime:
    return datetime.now(tz=KST)

def dt_kst(d: date, hour: int) -> datetime:
    return datetime(d.year, d.month, d.day, hour, 0, 0, tzinfo=KST)

def parse_pubdate_to_kst(pubdate_str: str) -> datetime:
    try:
        dt = parsedate_to_datetime(pubdate_str)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt.astimezone(KST)
    except Exception:
        return datetime.min.replace(tzinfo=KST)


# -----------------------------
# Article Body Crawling (본문 보강)
# -----------------------------
# 네이버 API description(1-2문장 스니펫)을 원문 본문으로 보강하여
# 점수 정확도를 높인다. 방송사 영상 리포트 등 스니펫이 짧은 기사도
# 원문 크롤링으로 충분한 텍스트를 확보할 수 있다.
_BODY_CRAWL_ENABLED = os.getenv("BODY_CRAWL_ENABLED", "true").strip().lower() in ("1", "true", "yes", "y")
_BODY_CRAWL_MAX_WORKERS = max(1, min(int(os.getenv("BODY_CRAWL_MAX_WORKERS", "10") or "10"), 20))
_BODY_CRAWL_TIMEOUT = 5.0  # connect timeout (접속 불가 서버 빠른 탈락)
_BODY_CRAWL_READ_TIMEOUT = 10.0  # read timeout (본문 수신)
_BODY_CRAWL_MAX_CHARS = 2000
_BODY_CACHE: dict[str, str] = {}
_BODY_CACHE_LOCK = threading.Lock()
_BODY_CACHE_MAX = 2000  # evict all when exceeded to prevent OOM

# 크롤링 전용 세션: retry 1회 + 짧은 connect timeout (공용 http_session과 분리)
_BODY_SESSION_LOCAL = threading.local()

def _body_crawl_session() -> requests.Session:
    s = getattr(_BODY_SESSION_LOCAL, "session", None)
    if s is None:
        s = requests.Session()
        retry = Retry(total=1, connect=1, read=1, backoff_factor=0.3,
                      status_forcelist=[429, 500, 502, 503, 504])
        adapter = HTTPAdapter(max_retries=retry)
        s.mount("https://", adapter)
        s.mount("http://", adapter)
        _BODY_SESSION_LOCAL.session = s
    return s

_BODY_ARTICLE_SELECTORS = [
    # 주요 뉴스사 본문 영역 패턴 (class/id)
    r'<article[^>]*>(.*?)</article>',
    r'<div[^>]*(?:id|class)=["\'](?:article[_-]?[Bb]ody|news[_-]?[Cc]ontent|article[_-]?[Cc]ontent|newsView|articleText|article_txt|story_body|view_txt|view_cont|viewConts|articeBody|news_view)["\'][^>]*>(.*?)</div>',
]

_BODY_EXCLUDE_TAGS_RE = re.compile(r'<(?:script|style|noscript|iframe|svg|nav|footer|header|aside)[^>]*>.*?</(?:script|style|noscript|iframe|svg|nav|footer|header|aside)>', re.I | re.S)
_BODY_TAG_RE = re.compile(r'<[^>]+>')
_BODY_WHITESPACE_RE = re.compile(r'\s+')


def _extract_body_from_html(html_text: str) -> str:
    """HTML에서 기사 본문 텍스트를 추출. 실패 시 빈 문자열."""
    if not html_text:
        return ""

    # 1순위: og:description (가장 안정적인 요약)
    og_desc = ""
    og_m = re.search(r'property=["\']og:description["\']\s*content=["\']([^"\']+)["\']', html_text, re.I)
    if og_m:
        og_desc = html.unescape(og_m.group(1)).strip()

    # 2순위: article/본문 영역 내 텍스트
    body_text = ""
    for pattern in _BODY_ARTICLE_SELECTORS:
        m = re.search(pattern, html_text, re.I | re.S)
        if m:
            raw = m.group(1)
            raw = _BODY_EXCLUDE_TAGS_RE.sub(" ", raw)
            raw = _BODY_TAG_RE.sub(" ", raw)
            raw = html.unescape(raw)
            raw = _BODY_WHITESPACE_RE.sub(" ", raw).strip()
            if len(raw) >= 50:
                body_text = raw
                break

    # 3순위: 전체 <p> 태그에서 50자 이상만 결합
    if not body_text:
        paragraphs = re.findall(r'<p[^>]*>(.*?)</p>', html_text, re.I | re.S)
        parts = []
        for p in paragraphs:
            cleaned = _BODY_TAG_RE.sub(" ", p)
            cleaned = html.unescape(cleaned)
            cleaned = _BODY_WHITESPACE_RE.sub(" ", cleaned).strip()
            if len(cleaned) >= 30:
                parts.append(cleaned)
        if parts:
            body_text = " ".join(parts)

    # og:description + body_text 결합 (중복 제거)
    if og_desc and body_text:
        if og_desc not in body_text:
            combined = og_desc + " " + body_text
        else:
            combined = body_text
    elif body_text:
        combined = body_text
    elif og_desc:
        combined = og_desc
    else:
        return ""

    return combined[:_BODY_CRAWL_MAX_CHARS].strip()


def _crawl_article_body(url: str) -> str:
    """기사 원문 URL에서 본문 텍스트 추출. 캐시 우선, 실패 시 빈 문자열."""
    url = (url or "").strip()
    if not url:
        return ""

    cache_key = hashlib.sha256(url.encode("utf-8")).hexdigest()[:16]
    with _BODY_CACHE_LOCK:
        cached = _BODY_CACHE.get(cache_key)
    if cached is not None:
        return cached

    body = ""
    try:
        r = _body_crawl_session().get(url, timeout=(_BODY_CRAWL_TIMEOUT, _BODY_CRAWL_READ_TIMEOUT), headers={
            "User-Agent": "Mozilla/5.0 (compatible; agri-news-brief/1.0)",
        })
        if r.ok:
            body = _extract_body_from_html(r.text or "")
    except Exception as exc:
        log.debug("[BODY CRAWL] failed url=%s: %s", url[:80], exc)

    with _BODY_CACHE_LOCK:
        if len(_BODY_CACHE) >= _BODY_CACHE_MAX:
            _BODY_CACHE.clear()
            log.debug("[BODY CRAWL] cache evicted (limit=%d)", _BODY_CACHE_MAX)
        _BODY_CACHE[cache_key] = body
    return body


def _enrich_article_bodies(articles: list["Article"], *, max_workers: int | None = None) -> int:
    """기사 목록의 description을 원문 본문으로 보강. 성공 건수 반환."""
    if not _BODY_CRAWL_ENABLED or not articles:
        return 0

    workers = max_workers or _BODY_CRAWL_MAX_WORKERS
    enriched = 0

    # 크롤링 본문 품질 검증: 비기사 텍스트(JS 안내, 저작권, 댓글 등) 비율이 높으면 거부
    _noise_markers = ("센스리더", "동영상플레이어", "저작권", "Copyright", "댓글 이용시",
                      "방향키는 시간이", "스페이스 바를 누르시면", "읽어주기 기능은")

    def _enrich_one(art: "Article") -> bool:
        is_broadcast = (getattr(art, "press", "") or "").strip() in BROADCAST_PRESS
        # 방송사: 네이버 뉴스 URL(link)로 크롤링 (원문에 스크립트 없음)
        # 일반 매체: 원문 URL(originallink) 우선, 실패 시 네이버 URL(link) fallback
        primary_url = ""
        fallback_url = ""
        if is_broadcast:
            primary_url = getattr(art, "link", "") or ""
            fallback_url = getattr(art, "originallink", "") or ""
        else:
            primary_url = getattr(art, "originallink", "") or ""
            fallback_url = getattr(art, "link", "") or ""
        if not primary_url and not fallback_url:
            return False
        body = _crawl_article_body(primary_url) if primary_url else ""
        # 원문 실패/부족 시 네이버 URL로 fallback
        if (not body or len(body) <= len(art.description or "")) and fallback_url and fallback_url != primary_url:
            body_fb = _crawl_article_body(fallback_url)
            if body_fb and len(body_fb) > len(body or ""):
                body = body_fb
        if not body or len(body) <= len(art.description or ""):
            return False
        # 품질 검증: 노이즈 마커가 2개 이상이면 거부
        noise_count = sum(1 for m in _noise_markers if m.lower() in body.lower())
        if noise_count >= 2:
            return False
        art.description = body
        return True

    with ThreadPoolExecutor(max_workers=workers) as ex:
        futures = {ex.submit(_enrich_one, art): art for art in articles}
        for fut in as_completed(futures):
            try:
                if fut.result():
                    enriched += 1
            except Exception:
                pass

    return enriched


def _best_effort_article_pubdate_kst(url: str) -> datetime | None:
    """Best-effort article publish datetime extraction (KST).

    - 1차: URL 패턴(예: newsis NISXYYYYMMDD)에서 날짜 추정
    - 2차: 본문 HTML 메타태그에서 datetime 추출(가벼운 regex)
    """
    try:
        u = str(url or "").strip()
        if not u:
            return None

        m = re.search(r"NISX(\d{8})", u)
        if m:
            ds = m.group(1)
            d = datetime.strptime(ds, "%Y%m%d").date()
            return datetime(d.year, d.month, d.day, 12, 0, 0, tzinfo=KST)

        r = _body_crawl_session().get(u, timeout=(_BODY_CRAWL_TIMEOUT, 10))
        if not r.ok:
            return None
        txt = r.text or ""

        pats = [
            r'article:published_time"\s*content="([^"]+)"',
            r'property="og:published_time"\s*content="([^"]+)"',
            r'name="pubdate"\s*content="([^"]+)"',
            r'itemprop="datePublished"\s*content="([^"]+)"',
            r'"datePublished"\s*:\s*"([^"]+)"',
        ]
        cand = None
        for ptn in pats:
            mm = re.search(ptn, txt, flags=re.I)
            if mm:
                cand = (mm.group(1) or "").strip()
                break
        if not cand:
            return None

        cand2 = cand.replace("Z", "+00:00")
        try:
            dt = datetime.fromisoformat(cand2)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=KST)
            return dt.astimezone(KST)
        except Exception:
            pass

        m2 = re.search(r"(20\d{2})[-./](\d{1,2})[-./](\d{1,2})(?:\s+[T]?(\d{1,2}):(\d{2}))?", cand)
        if m2:
            yy, mo, dd = int(m2.group(1)), int(m2.group(2)), int(m2.group(3))
            hh = int(m2.group(4)) if m2.group(4) else 12
            mi = int(m2.group(5)) if m2.group(5) else 0
            return datetime(yy, mo, dd, hh, mi, 0, tzinfo=KST)
    except Exception:
        return None
    return None


def _date_hint_from_url(url: str) -> date | None:
    try:
        parsed = urlparse(str(url or "").strip())
        path = parsed.path or ""
        for ptn in (r"/(20\d{2})/(\d{2})/(\d{2})(?:/|$)", r"/article/(20\d{2})(\d{2})(\d{2})\d*"):
            mm = re.search(ptn, path)
            if not mm:
                continue
            yy, mo, dd = int(mm.group(1)), int(mm.group(2)), int(mm.group(3))
            return date(yy, mo, dd)
        mm2 = re.search(r"(20\d{2})(\d{2})(\d{2})", path)
        if mm2:
            yy, mo, dd = int(mm2.group(1)), int(mm2.group(2)), int(mm2.group(3))
            return date(yy, mo, dd)
    except Exception:
        return None
    return None


def clean_text(s: str) -> str:
    if not s:
        return ""
    s = html.unescape(s)
    s = re.sub(r"<[^>]+>", " ", s)
    s = re.sub(r"\s+", " ", s).strip()
    return s

def domain_of(url: str) -> str:
    """URL의 도메인(호스트명).
    - m., www. 같은 일반 서브도메인은 제거해 매체 매핑/중복키/필터가 일관되게 동작하도록 한다.
    """
    try:
        u = urlparse(url)
        host = (u.hostname or "").lower()
        if host.startswith("www."):
            host = host[4:]
        if host.startswith("m."):
            host = host[2:]
        return host
    except Exception:
        return ""

def strip_tracking_params(url: str) -> str:
    try:
        u = urlparse(url)
        q = [(k, v) for (k, v) in parse_qsl(u.query, keep_blank_values=True)
             if not k.lower().startswith("utm_") and k.lower() not in ("gclid", "fbclid", "igshid", "ref", "outurl", "nclick")]
        new_q = urlencode(q, doseq=True)
        return urlunparse((u.scheme, u.netloc, u.path, u.params, new_q, u.fragment))
    except Exception:
        return url

def canonicalize_url(url: str) -> str:
    url = strip_tracking_params(url or "").strip()
    if not url:
        return ""
    try:
        u = urlparse(url)
        host = (u.hostname or "").lower()
        for pfx in ("www.", "m.", "mobile."):
            if host.startswith(pfx):
                host = host[len(pfx):]
        scheme = "https" if u.scheme in ("http", "https") else "https"
        netloc = host
        path = u.path or "/"
        frag = ""
        return urlunparse((scheme, netloc, path, "", u.query or "", frag))
    except Exception:
        return url

def norm_title_key(title: str) -> str:
    t = (title or "").lower()
    t = re.sub(r"\[[^\]]+\]", " ", t)
    t = re.sub(r"\([^)]*\)", " ", t)
    t = re.sub(r"[^0-9a-z가-힣]+", "", t)
    return t[:90]

