def _editorial_safe_text(article: "Article") -> str:
    return _nfkc_lower(f"{getattr(article, 'title', '') or ''} {getattr(article, 'description', '') or ''}")


def _editorial_safe_has_any(text: str, terms: tuple[str, ...]) -> bool:
    return any(term and term.lower() in text for term in terms)


def is_dist_market_education_tail_context(title: str, desc: str) -> bool:
    text = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    if not text:
        return False
    education_hits = count_any(text, [w.lower() for w in _EDITORIAL_SAFE_DIST_EDUCATION_TERMS])
    market_hits = count_any(
        text,
        [w.lower() for w in ("동화청과", "도매시장", "대형 유통업체", "구매·판매", "구매 판매", "출하 전략", "판로", "산지-유통")],
    )
    return education_hits >= 2 and market_hits >= 2


def is_dist_hard_logistics_metric_context(title: str, desc: str) -> bool:
    text = _nfkc_lower(f"{title or ''} {desc or ''}")
    if not text:
        return False
    support_grant_hits = count_any(
        text,
        [w.lower() for w in ("물류기자재", "기자재 지원", "지원금 전달", "후원금 전달", "생산 안정", "생산안정")],
    )
    physical_ops_hits = count_any(
        text,
        [w.lower() for w in ("물류비", "운송비", "하역", "반입량", "처리물량", "정산", "순회수집", "파렛트", "팰릿")],
    )
    if support_grant_hits >= 1 and physical_ops_hits <= 0:
        return False
    if not (
        _editorial_safe_has_any(text, ("가락시장", "도매시장", "공판장"))
        and _editorial_safe_has_any(text, ("파렛트", "팰릿", "물류", "운송지원", "운송 지원"))
    ):
        return False
    hard_ops_hits = count_any(
        text,
        [w.lower() for w in (
            "출하량", "출하율", "거래액", "물류비", "운송비", "물동량", "반입량", "처리물량",
            "지원금", "하역", "정산", "감축", "절감", "순회수집",
        )],
    )
    has_metric_ops = bool(re.search(
        r"(?:출하량|출하율|거래액|물류비|운송비|지원금|물동량|반입량|처리물량|경매가|경락가).{0,24}\d"
        r"|\d[\d,]*(?:\.\d+)?\s*(?:톤|t|kg|억원|만원|원|%|%포인트|포인트|건|상자|박스|ha|㏊).{0,24}"
        r"(?:출하|거래|물류|반입|정산|경매|경락|수출|운송|처리|하역|파렛트|팰릿|지원)",
        text,
        re.IGNORECASE,
    ))
    return hard_ops_hits >= 2 or has_metric_ops


def is_dist_national_export_logistics_context(title: str, desc: str, dom: str = "", press: str = "") -> bool:
    """농식품/K-푸드 수출이 물류 리스크와 수치로 함께 설명되는 전국성 유통 기사."""
    raw_text = unicodedata.normalize("NFKC", f"{title or ''} {desc or ''}".strip())
    text = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    title_l = _nfkc_lower(title or "")
    if not text:
        return False
    export_hits = count_any(text, [w.lower() for w in ("수출", "해외", "gcc", "중동", "중국", "미국")])
    food_hits = count_any(text, [w.lower() for w in ("k-푸드", "k푸드", "농식품", "한국 식품", "식품기업", "한국농수산식품유통공사")])
    if re.search(r"(?<![A-Za-z0-9])aT(?![A-Za-z0-9])", raw_text):
        food_hits += 1
    logistics_hits = count_any(
        text,
        [w.lower() for w in ("물류난", "물류 차질", "해상 물류", "운임", "우회 운송", "물류비", "수출바우처", "물류 부담")],
    )
    shock_hits = count_any(text, [w.lower() for w in ("중동전쟁", "중동 전쟁", "전쟁", "홍해", "호르무즈", "위기")])
    has_metric = bool(re.search(r"\d[\d,]*(?:\.\d+)?\s*(?:%|달러|억원|만\s*달러|억\s*달러)", text))
    title_signal = count_any(
        title_l,
        [w.lower() for w in ("중동", "물류", "수출", "k-푸드", "k푸드", "gcc")],
    )
    response_hits = count_any(text, [w.lower() for w in ("정부", "농식품부", "대응", "지원", "방어", "총력", "수출바우처")])
    if food_hits < 1 or logistics_hits < 1:
        return False
    if export_hits < 1 and response_hits < 2:
        return False
    if not has_metric and not (shock_hits >= 1 and response_hits >= 2 and title_signal >= 3):
        return False
    if title_signal >= 2:
        return True
    return shock_hits >= 1 and (press_priority(press, dom) >= 2 or "농식품부" in text or "aT" in text)


def is_dist_export_logistics_response_context(title: str, desc: str, dom: str = "", press: str = "") -> bool:
    if not is_dist_national_export_logistics_context(title, desc, dom, press):
        return False
    text = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    title_l = _nfkc_lower(title or "")
    response_hits = count_any(text, [w.lower() for w in ("정부", "농식품부", "대응", "지원", "방어", "총력", "수출바우처", "물류비 지원")])
    title_response_hits = count_any(
        title_l,
        [w.lower() for w in ("정부", "농식품부", "대응", "지원", "방어", "총력", "수출바우처", "중동발 충격", "충격 확산")],
    )
    risk_hits = count_any(text, [w.lower() for w in ("중동발 충격", "충격 확산", "물류 차질", "물류 부담")])
    return response_hits >= 2 and risk_hits >= 1 and title_response_hits >= 1


def is_dist_specific_kfood_export_logistics_context(title: str, desc: str, dom: str = "", press: str = "") -> bool:
    if not is_dist_national_export_logistics_context(title, desc, dom, press):
        return False
    text = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    if is_dist_export_logistics_response_context(title, desc, dom, press):
        return False
    specific_hits = count_any(text, [w.lower() for w in ("gcc", "중동 수출", "물류난", "해상 물류", "우회 운송", "운임", "딸기", "수출 37")])
    return specific_hits >= 2


def is_dist_labor_issue_without_logistics_action(title: str, desc: str) -> bool:
    text = _nfkc_lower(f"{title or ''} {desc or ''}")
    if not text:
        return False
    if is_dist_hard_logistics_metric_context(title, desc):
        return False
    return (
        _editorial_safe_has_any(text, ("가락시장", "도매시장"))
        and _editorial_safe_has_any(text, ("하역노동", "하역 노동", "노동자", "주5일", "근무", "인력"))
        and not _editorial_safe_has_any(text, ("물류비", "운송지원", "파렛트", "정산", "출하율", "반입량", "처리물량"))
    )


_CORE_OPINION_TITLE_MARKERS = (
    "취재수첩", "기자수첩", "데스크칼럼", "칼럼", "기고", "사설", "오피니언", "독자기고", "기자의 눈",
)
_CORE_CEREMONY_TITLE_TERMS = (
    "취임", "이임", "부임", "연임", "위촉", "임명장", "선출", "당선", "표창", "시상",
    "수상", "포상", "기념식", "개소식", "준공식", "선포식", "발대식", "출범식", "이취임",
)
_CORE_EDU_VISIT_TITLE_TERMS = (
    "견학", "체험", "배웠다", "배운다", "배우다", "연수", "워크숍", "특강", "초청",
    "벤치마킹", "교육",
    "민생 행보", "민생 현장", "현장 행보", "영농상담", "찾아간다",
)
# 회의체 명칭은 단체 이름의 일부일 수 있어(예: ○○상생협의회의 반대 성명),
# 제목에 개최·참석류 동사가 함께 있을 때만 행사 기사로 판정한다.
_CORE_MEETING_EVENT_TERMS = ("협의회", "간담회", "세미나", "포럼")
_CORE_MEETING_EVENT_VERB_RX = re.compile(r"열|개최|가졌|참석|성료")
_CORE_PROMO_TITLE_TERMS = (
    "특별전", "판촉", "판매전", "홍보", "캠페인", "페스티벌", "축제", "시식", "증정",
    "경품", "팔아주기", "기탁", "전달식", "나눔", "자매결연", "맞손", "업무협약", "협약",
    "개점", "개업",
)
_CORE_ADMIN_INTERNAL_TITLE_TERMS = (
    "실행계획 수립", "경영평가", "경영혁신", "조직개편", "비전 선포", "청렴", "윤리경영",
    "공급 완료", "지원 완료", "보급 완료", "접수 완료", "추진 실적",
)
# 조합·법인의 물품 지원(자재·장비·기증) 홍보 기사 — 시장 신호 수치 없으면 소프트뉴스
_CORE_SUPPORT_GRANT_RX = re.compile(
    r"(?:물품|자재|장비|기자재|농자재|물류기자재|트랩|방제기).{0,12}(?:지원|기증|전달|보급|공급|할인)"
)
_CORE_SUPPORT_GRANT_ORG_RX = re.compile(
    r"[가-힣A-Za-z]{1,12}(?:청과|농협|조합|공판장|연합회)[,\s].{0,20}(?:지원|기증|전달)"
)
def _has_market_metric_evidence(text: str) -> bool:
    """가격·물량 수치가 시장 맥락과 함께 등장하는지(소프트뉴스 강등의 유일한 예외)."""
    body = _nfkc_lower(text or "")
    if not body:
        return False
    # NOTE: 한글은 \w에 포함되어 \b가 단위+조사('톤을') 사이에서 성립하지 않으므로
    #       라틴 문자 연속 방지 lookahead로 단위 경계를 판정한다
    return bool(re.search(
        r"\d[\d,]*(?:\.\d+)?\s*(?:톤|t|㎏|kg|억원|만원|원|%|ha|㏊|상자|박스)(?![A-Za-z]).{0,30}"
        r"(?:가격|시세|출하|반입|경매|경락|물량|생산|수급|거래|피해|방제|수매|안정|방출|비축)"
        r"|(?:가격|시세|값|출하량|반입량|경매가|경락가|최고가|물량|생산량|피해).{0,16}\d",
        body,
        re.IGNORECASE,
    ))


def _soft_news_core_demote_reason(article: "Article") -> str:
    """행사·교육·인사·판촉·칼럼 등 소프트뉴스는 섹션 불문 core 승격을 금지한다.
    tail 카드로는 남을 수 있으나 핵심 슬롯은 하드뉴스가 차지해야 한다."""
    title = str(getattr(article, "title", "") or "").strip()
    if not title:
        return ""
    title_l = _nfkc_lower(title)
    if is_news_roundup_brief_context(title, getattr(article, "description", "") or ""):
        return "roundup_brief_core"
    # '[2일 ○○도] … 등' 형태의 지역 동정 라운드업 제목
    if re.match(r"^\s*[\[〔【]", title) and re.search(r"(?:등|외)\s*$", title):
        return "regional_roundup_core"
    # '[주간농사메모]' 같은 고정 코너 안내는 당일 뉴스가 아니라 상시 가이드
    if re.match(r"^\s*[\[〔【]\s*(?:주간|월간|금주|오늘의)", title):
        return "recurring_guide_core"
    # 과거 회고·연대기성 기획은 당일 핵심 뉴스가 아니다
    if re.search(r"(?:19|20)\d0년대", title) or any(t in title_l for t in ("회고", "돌아본", "그때 그")):
        return "retrospective_feature_core"
    if any(marker in title_l for marker in _CORE_OPINION_TITLE_MARKERS):
        return "opinion_column_core"
    text = _editorial_safe_text(article)
    # 행사·교육·판촉 제목이라도 구체적 가격·물량 수치가 있으면 시장 뉴스로 취급
    if _has_market_metric_evidence(text):
        return ""
    if any(term in title_l for term in _CORE_CEREMONY_TITLE_TERMS):
        return "soft_news_ceremony_core"
    if any(term in title_l for term in _CORE_EDU_VISIT_TITLE_TERMS):
        return "soft_news_education_core"
    if (
        any(term in title_l for term in _CORE_MEETING_EVENT_TERMS)
        and _CORE_MEETING_EVENT_VERB_RX.search(title_l)
    ):
        return "soft_news_education_core"
    if any(term in title_l for term in _CORE_PROMO_TITLE_TERMS):
        return "soft_news_promo_core"
    if any(term in title_l for term in _CORE_ADMIN_INTERNAL_TITLE_TERMS):
        return "soft_news_admin_internal_core"
    if _CORE_SUPPORT_GRANT_RX.search(title_l) or _CORE_SUPPORT_GRANT_ORG_RX.search(title):
        return "soft_news_support_grant_core"
    return ""


_PEST_ACTIVE_RISK_TITLE_TERMS = (
    "방제", "발생", "확산", "피해", "예찰", "비상", "주의", "경보", "감염", "고사",
    "매몰", "확진", "냉해", "우박", "일소", "침수", "차단",
)


def _editorial_safe_core_demote_reason(article: "Article", section_key: str) -> str:
    if section_key not in {"supply", "policy", "dist", "pest"}:
        return ""
    if section_key == "pest":
        soft = _soft_news_core_demote_reason(article)
        if soft:
            return soft
        # pest core는 당일 발생·확산·방제 등 활성 리스크 신호가 제목에 있어야 한다
        # (방제 편의 기술·품종 보급·AI 서비스 소개류는 tail로만)
        pest_title = _nfkc_lower(getattr(article, "title", "") or "")
        if pest_title and not any(term in pest_title for term in _PEST_ACTIVE_RISK_TITLE_TERMS):
            return "pest_no_active_risk_core"
        return ""
    text = _editorial_safe_text(article)
    title_l = _nfkc_lower(getattr(article, "title", "") or "")
    if section_key == "supply":
        if _is_supply_agritech_research_story(article):
            return "supply_agritech_research_core"
        if is_dist_market_education_tail_context(getattr(article, "title", "") or "", getattr(article, "description", "") or ""):
            return "supply_dist_market_education_tail"
        nonfood_hits = count_any(text, tuple(term.lower() for term in _EDITORIAL_SAFE_SUPPLY_NONFOOD_PRODUCT_TERMS))
        nonfood_compact_hit = _contains_compact_marker(text, _EDITORIAL_SAFE_SUPPLY_NONFOOD_PRODUCT_TERMS)
        if nonfood_hits or nonfood_compact_hit:
            market_hits = count_any(text, tuple(term.lower() for term in _EDITORIAL_SAFE_SUPPLY_CORE_MARKET_TERMS))
            title_market_hits = count_any(title_l, tuple(term.lower() for term in _EDITORIAL_SAFE_SUPPLY_CORE_MARKET_TERMS))
            if title_market_hits == 0 and market_hits <= 1:
                return "supply_nonfood_promo_without_market_signal"
    if section_key == "dist":
        if _is_dist_market_ceremony_story(article):
            return "dist_market_ceremony_core"
        if is_dist_national_export_logistics_context(
            getattr(article, "title", "") or "",
            getattr(article, "description", "") or "",
            getattr(article, "domain", "") or "",
            getattr(article, "press", "") or "",
        ):
            return ""
        if "물류 선진화" in title_l and "파렛트" in title_l and "운송지원" in title_l and "확대" in title_l:
            if not is_dist_hard_logistics_metric_context(getattr(article, "title", "") or "", getattr(article, "description", "") or ""):
                return "promotional_or_event_filler"
        if is_dist_labor_issue_without_logistics_action(getattr(article, "title", "") or "", getattr(article, "description", "") or ""):
            return "dist_labor_issue_without_logistics_action"
        if (
            _editorial_safe_has_any(text, ("운송지원", "운송 지원"))
            and _editorial_safe_has_any(text, ("파렛트", "팰릿", "물류 선진화", "운송지원 확대", "운송 지원 확대"))
        ):
            if not is_dist_hard_logistics_metric_context(getattr(article, "title", "") or "", getattr(article, "description", "") or ""):
                return "promotional_or_event_filler"
        if (
            _editorial_safe_has_any(text, _EDITORIAL_SAFE_DIST_PRODUCTION_POLICY_TERMS)
            and not _editorial_safe_has_any(title_l, (
                "가락시장", "도매시장", "공판장", "apc", "산지유통", "농산물 유통", "유통협력",
                "유통 협력", "유통 효율", "온라인도매시장", "파렛트", "물류", "출하", "반입", "경락", "수출", "검역",
            ))
        ):
            return "dist_production_policy_without_ops"
        dist_event_core_terms = (
            "업무협약", "협약", "mou", "프로젝트", "벤치마킹", "간담회", "협의회", "현장투어",
        )
        if _editorial_safe_has_any(text, dist_event_core_terms):
            concrete_ops_hits = count_any(
                text,
                [w.lower() for w in (
                    "출하량", "거래액", "물류비", "물동량", "반입", "경매", "정산", "계약재배",
                    "수출 물량", "수출물량", "처리물량", "공선출하", "공동선별", "도매시장 반입",
                    "온라인도매시장", "가동", "준공",
                )],
            )
            has_metric_ops = bool(re.search(
                r"(?:출하량|거래액|물류비|물동량|반입량|처리물량|수출\s*물량|정산액|경매가).{0,16}\d"
                r"|\d[\d,]*(?:\.\d+)?\s*(?:톤|t|kg|억원|만원|원|%|건|상자|박스|ha|㏊).{0,16}"
                r"(?:출하|거래|물류|반입|정산|경매|수출|운송|처리)",
                text,
                re.IGNORECASE,
            ))
            if concrete_ops_hits < 2 and not has_metric_ops:
                return "dist_event_or_development_without_ops"
        if (
            _editorial_safe_has_any(text, _EDITORIAL_SAFE_DIST_EDUCATION_TERMS)
            or _contains_compact_marker(text, _EDITORIAL_SAFE_DIST_EDUCATION_TERMS)
        ):
            ops_hits = count_any(text, tuple(term.lower() for term in _EDITORIAL_SAFE_DIST_OPS_TERMS))
            title_education_hit = (
                _editorial_safe_has_any(title_l, _EDITORIAL_SAFE_DIST_EDUCATION_TERMS)
                or _contains_compact_marker(title_l, _EDITORIAL_SAFE_DIST_EDUCATION_TERMS)
            )
            has_hard_metric = (
                _editorial_safe_has_any(text, _EDITORIAL_SAFE_DIST_HARD_METRIC_TERMS)
                or bool(re.search(
                    r"(?:출하량|거래액|물류비|물동량|반입량|처리물량|수출\s*물량|정산액|경매가|경락가).{0,16}\d"
                    r"|\d[\d,]*(?:\.\d+)?\s*(?:톤|t|kg|억원|만원|원|%|건|상자|박스|ha|㏊).{0,16}"
                    r"(?:출하|거래|물류|반입|정산|경매|경락|수출|운송|처리)",
                    text,
                    re.IGNORECASE,
                ))
            )
            if not has_hard_metric and (title_education_hit or ops_hits <= 1):
                return "dist_education_or_training_without_ops"
        if (
            "출하" in title_l
            and _editorial_safe_has_any(text, ("할인 행사", "할인행사", "쇼핑몰", "브랜드", "홍보", "캠페인"))
            and not is_dist_hard_logistics_metric_context(getattr(article, "title", "") or "", getattr(article, "description", "") or "")
        ):
            return "promotional_or_event_filler"
    if section_key == "policy":
        if (
            any(term in title_l for term in ("[창간특집]", "[사설]", "[기고]", "[칼럼]"))
            and any(term in text for term in ("정부", "농정", "정책", "농업"))
        ):
            return "opinion_column_core"
        title_field_price = count_any(
            title_l,
            [w.lower() for w in (
                "값 폭락", "가격 폭락", "값 하락", "가격 하락", "캘수록 손해",
                "갈아엎", "밭 갈아", "농민들", "농가",
            )],
        )
        title_policy_actor = count_any(
            title_l,
            [w.lower() for w in (
                "정부", "농식품부", "농림축산식품부", "기재부", "농진청", "농촌진흥청",
                "지자체", "전북자치도", "충남도", "무주군",
            )],
        )
        policy_action_hits = count_any(
            text,
            [w.lower() for w in (
                "대책", "발표", "추진", "시행", "확대", "지원", "수매", "비축",
                "산지폐기", "할당관세", "점검", "공급", "수급", "안정",
            )],
        )
        if title_field_price >= 2 and title_policy_actor == 0:
            return "policy_field_price_collapse_without_policy_lead"
        if title_field_price >= 1 and title_policy_actor == 0 and policy_action_hits <= 1:
            return "policy_field_price_collapse_without_policy_lead"
        if _editorial_safe_has_any(text, _EDITORIAL_SAFE_POLICY_PRICE_TERMS) and not _editorial_safe_has_any(text, _EDITORIAL_SAFE_POLICY_ACTION_TERMS):
            return "policy_price_report_without_policy_action"
    if any(term in text for term in ("홈쇼핑", "라이브커머스", "쇼호스트", "현장투어")):
        return "promotional_or_event_filler"
    promo_hits = count_any(text, tuple(term.lower() for term in _EDITORIAL_SAFE_PROMO_TERMS))
    if promo_hits:
        market_hits = count_any(text, tuple(term.lower() for term in _EDITORIAL_SAFE_MARKET_TERMS))
        title_market_hits = count_any(title_l, tuple(term.lower() for term in _EDITORIAL_SAFE_MARKET_TERMS))
        dist_ops_action = section_key == "dist" and _editorial_safe_has_any(text, (
            "가락시장", "공영도매시장", "도매시장", "파렛트", "팰릿", "운송지원",
            "운송 지원", "물류비", "반입", "경매", "하역", "정산", "출하",
        ))
        if market_hits <= 1 and title_market_hits == 0 and not dist_ops_action:
            return "promotional_or_event_filler"
        if (
            section_key in {"supply", "dist"}
            and market_hits <= 2
            and _editorial_safe_has_any(text, ("지원", "행사", "협의회", "개최"))
            and not dist_ops_action
        ):
            return "promotional_or_event_filler"
    if section_key == "dist":
        weak_hits = count_any(text, tuple(term.lower() for term in _EDITORIAL_SAFE_DIST_WEAK_TERMS))
        if weak_hits:
            ops_hits = count_any(text, tuple(term.lower() for term in _EDITORIAL_SAFE_DIST_OPS_TERMS))
            if "현장투어" in text or "소득작목" in text or ops_hits <= 1:
                return "dist_event_or_development_without_ops"
    # 일반화 소프트뉴스 게이트 (기존 세부 사유가 모두 통과한 뒤 마지막으로 적용)
    return _soft_news_core_demote_reason(article)


def _editorial_safe_soft_penalty(article: "Article", section_key: str) -> float:
    reason = _editorial_safe_core_demote_reason(article, section_key)
    if not reason:
        return 0.0
    if reason == "policy_price_report_without_policy_action":
        return 2.4
    if reason == "policy_field_price_collapse_without_policy_lead":
        return 2.8
    if reason in {"dist_event_or_development_without_ops", "dist_education_or_training_without_ops", "dist_production_policy_without_ops"}:
        return 2.2
    if reason == "supply_nonfood_promo_without_market_signal":
        return 2.2
    return 1.8


def _has_trade_signal(txt: str) -> bool:
    t = (txt or "").lower()
    return any(x in t for x in (
        "관세", "할당관세", "무관세", "fta", "수입", "통관", "검역", "보세", "보세구역",
        "추천 취소", "집중관리", "관리 강화", "판매가격 보고", "유통 의무"
    ))


def _is_similar_story(a: "Article", b: "Article", section_key: str) -> bool:
    at, ad = _story_text(a)
    bt, bd = _story_text(b)
    a_txt = f"{at} {ad}"
    b_txt = f"{bt} {bd}"

    # supply/policy: 무역/관세/FTA/수입 신호 유무가 다르면 같은 이슈로 묶지 않음(핵심 이슈 누락 방지)
    if section_key in ("supply", "policy"):
        if _has_trade_signal(a_txt) != _has_trade_signal(b_txt):
            return False

    if section_key == "dist":
        a_scope = dist_market_disruption_scope(at, ad)
        b_scope = dist_market_disruption_scope(bt, bd)
        if a_scope and b_scope and {a_scope, b_scope} == {"systemic", "commodity_aftershock"}:
            return False
        a_sig = _section_story_signature(section_key, at, ad, getattr(a, "domain", "") or "", getattr(a, "press", "") or "")
        b_sig = _section_story_signature(section_key, bt, bd, getattr(b, "domain", "") or "", getattr(b, "press", "") or "")
        if a_sig and b_sig:
            return a_sig == b_sig

    if section_key == "supply":
        a_feature = supply_feature_context_kind(at, ad)
        b_feature = supply_feature_context_kind(bt, bd)
        if a_feature and b_feature:
            a_issue_bucket = supply_issue_context_bucket(at, ad)
            b_issue_bucket = supply_issue_context_bucket(bt, bd)
            if a_issue_bucket and b_issue_bucket and a_issue_bucket != b_issue_bucket:
                return False
            a_rep_terms = {TOPIC_REP_BY_TERM_L.get(term, term) for term in HORTI_ITEM_TERMS_L if term in a_txt}
            b_rep_terms = {TOPIC_REP_BY_TERM_L.get(term, term) for term in HORTI_ITEM_TERMS_L if term in b_txt}
            if not a_rep_terms:
                a_topic = (getattr(a, "topic", "") or "").strip()
                if a_topic:
                    a_rep_terms = {a_topic}
            if not b_rep_terms:
                b_topic = (getattr(b, "topic", "") or "").strip()
                if b_topic:
                    b_rep_terms = {b_topic}
            if a_rep_terms and b_rep_terms and not (a_rep_terms & b_rep_terms):
                if (not has_direct_supply_chain_signal(a_txt)) and (not has_direct_supply_chain_signal(b_txt)):
                    return False

    # supply/policy: 유가/에너지 동일 토픽 기사 → 같은 이슈로 간주(중복 제거)
    if section_key in ("supply", "policy"):
        _oil_kws = ("유가", "원유", "국제유가", "기름값", "휘발유", "경유", "석유", "에너지", "opec", "배럴")
        a_oil = count_any(a_txt.lower(), list(_oil_kws)) >= 2
        b_oil = count_any(b_txt.lower(), list(_oil_kws)) >= 2
        if a_oil and b_oil:
            # 둘 다 유가/에너지 primary → horti 품목이 다르지 않은 한 같은 이슈
            a_horti = best_horti_score(at, ad)
            b_horti = best_horti_score(bt, bd)
            if a_horti < 1.8 and b_horti < 1.8:
                return True

    # cross-section: 같은 품목+지역+이슈 키워드 조합이면 같은 이슈로 간주
    _REGION_TERMS = ("구미", "무안", "제주", "해남", "진도", "영천", "상주", "성주", "합천", "고흥",
                     "안동", "영양", "창녕", "함평", "남해", "밀양", "나주", "의성", "신안", "완도")
    a_lower = a_txt.lower()
    b_lower = b_txt.lower()
    a_commodities = {TOPIC_REP_BY_TERM_L.get(t, t) for t in HORTI_ITEM_TERMS_L if t in a_lower}
    b_commodities = {TOPIC_REP_BY_TERM_L.get(t, t) for t in HORTI_ITEM_TERMS_L if t in b_lower}
    shared_commodities = a_commodities & b_commodities
    if shared_commodities:
        a_regions = {r for r in _REGION_TERMS if r in a_lower}
        b_regions = {r for r in _REGION_TERMS if r in b_lower}
        shared_regions = a_regions & b_regions
        if shared_regions:
            # 같은 품목 + 같은 지역 = 같은 이슈
            _ISSUE_KWS = ("주산지", "지정", "생산", "재배", "출하", "수급", "가격", "피해", "방제", "작황")
            a_issue = any(k in a_lower for k in _ISSUE_KWS)
            b_issue = any(k in b_lower for k in _ISSUE_KWS)
            if a_issue and b_issue:
                return True

    # 인물명 + 기관명 + 이슈 키워드 기반 중복 감지:
    # 다른 매체가 같은 이슈를 다른 제목으로 보도하는 경우 동일 이슈로 판정
    # 인물명이 아닌 "기관+행위+대상" 핵심 명사 조합으로 판단 (인물명만으로는 다른 이슈가 묶일 위험)
    _DEDUP_ANCHOR_KWS = (
        "농협", "농식품부", "농림축산식품부", "aT", "농관원", "경제지주", "농업경제",
        "가락시장", "도매시장", "공판장", "산지유통", "온라인도매시장",
        "농산물", "농축산물",
    )
    _DEDUP_ACTION_KWS = (
        "수급", "안정", "점검", "대책", "출하", "가격", "휴업", "시범휴업",
        "만전", "총력", "확대", "지원", "개혁", "혁신",
    )
    a_anchors = {k for k in _DEDUP_ANCHOR_KWS if k in a_txt}
    b_anchors = {k for k in _DEDUP_ANCHOR_KWS if k in b_txt}
    a_actions = {k for k in _DEDUP_ACTION_KWS if k in a_txt}
    b_actions = {k for k in _DEDUP_ACTION_KWS if k in b_txt}
    shared_anchors = a_anchors & b_anchors
    shared_actions = a_actions & b_actions
    # 기관 1개 이상 + 행위 1개 이상 겹치고, 각각 행위 2개 이상이면 동일 이슈
    if len(shared_anchors) >= 1 and len(shared_actions) >= 1 and len(a_actions) >= 2 and len(b_actions) >= 2:
        # 단, 품목이 다르면 다른 이슈 (예: "사과 수급 안정" vs "양파 가격 안정")
        a_items = {t for t in HORTI_ITEM_TERMS_L if t in a_lower}
        b_items = {t for t in HORTI_ITEM_TERMS_L if t in b_lower}
        if a_items and b_items and not (a_items & b_items):
            pass  # 품목이 다르면 다른 이슈 → 중복 아님
        else:
            return True

    if section_key == "pest":
        a_region = _pest_region_or_fallback_key(a)
        b_region = _pest_region_or_fallback_key(b)
        if a_region and b_region and a_region != b_region:
            if is_pest_control_policy_context(a_txt) and is_pest_control_policy_context(b_txt):
                return False
    # 0) 섹션별 선언형 이벤트 시그니처가 있으면 우선 적용(정확도 높고 비용 낮음)
    if section_key in _EVENT_KEY_SECTIONS:
        sa = _section_story_signature(section_key, at, ad, getattr(a, "domain", "") or "", getattr(a, "press", "") or "")
        sb = _section_story_signature(section_key, bt, bd, getattr(b, "domain", "") or "", getattr(b, "press", "") or "")
        if sa and sb and sa == sb:
            return True
        if section_key == "dist" and sa and sb and sa != sb:
            return False

    # 1) 제목/요약 기반 근접 중복(타매체 재전송/표기 차이) 보강
    try:
        if _near_duplicate_title(a, b, section_key):
            return True
    except Exception:
        pass


    # 2) 앵커 겹침 + 3-gram Jaccard(섹션별 임계치)
    ah = getattr(a, "_story_anchors", None)
    if ah is None:
        ah = _anchor_hits(at, ad)
        setattr(a, "_story_anchors", ah)
    bh = getattr(b, "_story_anchors", None)
    if bh is None:
        bh = _anchor_hits(bt, bd)
        setattr(b, "_story_anchors", bh)

    inter = ah & bh
    if section_key == "dist":
        # dist는 보도자료 중복이 많으므로 앵커 조건 완화 + Jaccard로 보강
        if len(ah) < 2 or len(bh) < 2 or len(inter) < 2:
            return False
        thr = _DEDUP_JACCARD_THR_DIST
    elif section_key in ("supply", "policy"):
        if len(ah) < 2 or len(bh) < 2 or len(inter) < 2:
            return False
        thr = _DEDUP_JACCARD_THR_SUPPLY_POLICY
    else:
        if len(ah) < 2 or len(bh) < 2 or len(inter) < 2:
            return False
        thr = _DEDUP_JACCARD_THR_DEFAULT

    ta = getattr(a, "_story_tri", None)
    if ta is None:
        ta = _trigrams(_norm_story_text(at, ad))
        setattr(a, "_story_tri", ta)
    tb = getattr(b, "_story_tri", None)
    if tb is None:
        tb = _trigrams(_norm_story_text(bt, bd))
        setattr(b, "_story_tri", tb)

    return _jaccard(ta, tb) >= thr


def _title_bigram_set(s: str) -> set[str]:
    s = (s or "").strip()
    if len(s) < 2:
        return set()
    # 연속 2글자(바이그램) 기반 유사도: 특수문자 제거된 title_key에 잘 맞음
    return {s[i:i+2] for i in range(len(s) - 1)}

def _is_similar_title(k1: str, k2: str) -> bool:
    """제목 중복(유사) 판정.
    - 목적: 같은 이슈가 타매체로 반복될 때 core/final에서 중복 제거
    - 입력은 norm_title_key()로 정규화된 문자열을 가정(공백/특수문자 제거)
    """
    a = (k1 or "").strip()
    b = (k2 or "").strip()
    if not a or not b:
        return False
    if a == b:
        return True

    # 너무 짧은 키는 오탐 위험이 크므로, 포함관계만 제한적으로 허용
    la, lb = len(a), len(b)
    shorter, longer = (a, b) if la <= lb else (b, a)
    ls, ll = len(shorter), len(longer)

    if ls < _DEDUP_MIN_TITLE_KEY_LEN:
        # 10글자 미만은 사실상 제목 키로 신뢰하기 어려움
        return False

    # 포함관계: 짧은 키가 긴 키에 포함되면 동일 이슈로 봄
    # (짧은 키가 충분히 길면 길이 비율 완화 — 영암군 최저가격보장제 등)
    contain_ratio_thr = _DEDUP_CONTAIN_RATIO_LONG if ls >= _DEDUP_CONTAIN_RATIO_LEN_THR else _DEDUP_CONTAIN_RATIO_SHORT
    if shorter in longer and (ls / ll) >= contain_ratio_thr:
        return True

    # 문자열 유사도(SequenceMatcher)
    try:
        ratio = difflib.SequenceMatcher(None, a, b).ratio()
        if ratio >= _DEDUP_SEQ_RATIO_HIGH:
            return True
        # 경계 영역은 바이그램 자카드로 추가 확인(긴 제목에서만)
        if ratio >= _DEDUP_SEQ_RATIO_MID and min(la, lb) >= _DEDUP_SEQ_MIN_LEN_FOR_BIGRAM:
            ba = _title_bigram_set(a)
            bb = _title_bigram_set(b)
            if ba and bb:
                jac = len(ba & bb) / max(1, len(ba | bb))
                if jac >= _DEDUP_BIGRAM_JACCARD_THR:
                    return True
        # 중간 유사도(0.75~0.90) + 트라이그램 자카드가 높으면 동일 기사로 판정
        # (같은 이슈를 다른 언론사가 어순/접미사만 바꿔 보도하는 패턴 포착)
        if ratio >= 0.75 and min(la, lb) >= 12:
            ta = _trigrams(a)
            tb = _trigrams(b)
            if ta and tb:
                tri_jac = len(ta & tb) / max(1, len(ta | tb))
                if tri_jac >= 0.55:
                    return True
    except Exception:
        pass

    return False


# -----------------------------
# 사건(event) 단위 동일성 판정 (일반화)
# - 제목/본문에서 품목·행위자·행위·지역·수량 엔티티를 구조적으로 추출해
#   "매체만 다른 같은 사건" 또는 "같은 사건의 섹션 교차 재배치"를 판정한다.
# - 특정 기사 제목·URL·매체·날짜 하드코딩 없이 동작한다.
# -----------------------------
