def _nfkc_lower(text: str) -> str:
    return unicodedata.normalize("NFKC", str(text or "")).lower()


def _compact_match_text(text: str) -> str:
    normalized = _nfkc_lower(text)
    if not normalized:
        return ""
    return re.sub(r"[\s\-_~·ㆍ.,:;!?/\\'\"“”‘’()\[\]{}<>|]+", "", normalized)


def _contains_compact_marker(text: str, markers: Sequence[str]) -> bool:
    compact_text = _compact_match_text(text)
    if not compact_text:
        return False
    for marker in markers:
        compact_marker = _compact_match_text(marker)
        if compact_marker and compact_marker in compact_text:
            return True
    return False


# 2~3글자 짧은 품목명이 다른 단어 내부에서 오탐되는 것을 방지하는 FP 복합어 목록.
# 예: "유자" in "보유자"(채권 보유자) → 오탐, "매실" in "판매실적" → 오탐
# 해당 복합어를 텍스트에서 마스킹한 뒤 품목명이 여전히 남아있는지 확인한다.
_SHORT_TERM_FALSE_POSITIVE_WORDS: dict[str, tuple[str, ...]] = {
    "유자": ("보유자", "소유자", "점유자", "공유자", "전유자", "채유자",
             "관유자", "임유자", "피보유자", "비소유자"),
    "매실": ("판매실", "거래실", "매실적"),
    "감자": ("투자감자", "감자본"),  # 주식 감자(감자본)
    "딸기": ("산딸기", "뱀딸기", "멍석딸기", "겨울딸기", "땅딸기", "복분자딸기", "산딸기나무"),
    # 사과대추는 대추의 한 품종으로, 사과 품목 기사로 연결하면 안 된다.
    "사과": ("사과대추", "사과 대추"),
}


_GREEN_ONION_SPORTS_HOMONYM_RE = re.compile(
    r"(?:\d+\s*(?:[-:]\s*|대\s*)\d+|슈팅수|퇴장|월드컵|축구|야구|농구|배구|"
    r"개최국|카타르|캐나다|득점|골|승리|완승|제압|꺾(?:고|은|었다|는)?).{0,28}대파"
    r"|대파.{0,18}(?:승리|완승|제압|꺾)"
)


def is_green_onion_sports_homonym_context(title: str, desc: str = "") -> bool:
    txt = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    return bool(txt and "대파" in txt and _GREEN_ONION_SPORTS_HOMONYM_RE.search(txt))


def _short_term_has_real_match(term: str, text: str) -> bool:
    """짧은 품목명(2~3글자)의 FP 복합어를 마스킹한 뒤 실제 매칭 여부를 반환."""
    if term not in text:
        return False
    fp_words = _SHORT_TERM_FALSE_POSITIVE_WORDS.get(term)
    if not fp_words:
        return True
    masked = text
    for fp in fp_words:
        masked = masked.replace(fp, "\x00" * len(fp))
    return term in masked


def _managed_commodity_matches_text(item: dict[str, Any], text: str, topic: str = "") -> bool:
    txt = (text or "").lower()
    if not txt:
        return False

    key = str(item.get("key") or "").strip()
    if key == "carrot" and "당근" in txt and not is_edible_carrot_context(txt):
        return False
    if key == "potato" and "감자" in txt and not is_fresh_potato_context(txt):
        return False
    if key == "eggplant" and "가지" in txt and not is_edible_eggplant_context(txt):
        return False

    if key == "green_onion" and is_green_onion_sports_homonym_context(txt):
        return False

    for term in item.get("match_terms") or []:
        term_l = str(term or "").strip().lower()
        if key == "napa_cabbage" and term_l == "배추":
            if re.search(r"(?<!양)배추", txt):
                return True
            continue
        if len(term_l) >= 2:
            if len(term_l) <= 3:
                if _short_term_has_real_match(term_l, txt):
                    return True
            elif term_l in txt:
                return True

    for term in item.get("context_terms") or []:
        term_l = str(term or "").strip().lower()
        if term_l and term_l in txt:
            return True

    for pattern in _MANAGED_COMMODITY_CONTEXT_PATTERNS.get(key, []):
        if pattern.search(txt):
            return True
    return False


def is_commodity_corporate_stock_context(title: str, desc: str) -> bool:
    ttl = _nfkc_lower(title or "")
    txt = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    if not txt:
        return False
    title_keep_hits = count_any(ttl, list(_COMMODITY_BOARD_DIRECT_AGRI_KEEP_TERMS))
    keep_hits = count_any(txt, list(_COMMODITY_BOARD_DIRECT_AGRI_KEEP_TERMS))
    finance_hits = count_any(txt, list(_COMMODITY_CORPORATE_STOCK_TERMS))
    corp_title_hits = count_any(ttl, list(_COMMODITY_CORPORATE_STOCK_TERMS))
    finance_market_hits = count_any(
        txt,
        [
            "주가", "주식", "증권", "상한가", "장중", "거래대금", "거래량", "코스피", "코스닥",
            "목표주가", "투자의견", "영업이익", "밸류에이션", "시총", "상장", "투자자",
            "테마주", "종목", "특징주", "액면병합", "거래 재개", "기준가", "변경상장",
            "광통신", "레이저다이오드", "주파수", "데이터센터", "ai 인프라",
        ],
    )
    company_suffix_hit = re.search(
        r"[가-힣a-z0-9]{1,}(?:\s+)?(?:솔루션|테크|전자|바이오|시스템|홀딩스|통신|네트웍스|네트워크|장비|반도체|모빌리티|미디어|로보틱스)",
        ttl,
    ) is not None
    explicit_finance_title_hit = re.search(
        r"(?:목표주가|투자의견|매수|매도|실적|영업이익|주가|증권|상향|하향|밸류에이션|상한가|장중|거래대금|거래량|테마주|종목|특징주|액면병합|거래\s*재개|기준가|변경상장|광통신|데이터센터)",
        ttl,
    ) is not None
    if title_keep_hits == 0 and explicit_finance_title_hit:
        return True
    if title_keep_hits == 0 and company_suffix_hit and finance_market_hits >= 2:
        return True
    if keep_hits >= 1:
        return False
    return (
        title_keep_hits == 0
        and (
            finance_market_hits >= 3
            or (company_suffix_hit and finance_market_hits >= 1)
            or (finance_hits >= 3 and corp_title_hits >= 1)
        )
    )


def is_commodity_foodservice_lifestyle_context(title: str, desc: str) -> bool:
    ttl = _nfkc_lower(title or "")
    txt = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    if not txt:
        return False
    keep_hits = count_any(txt, list(_COMMODITY_BOARD_MARKET_KEEP_TERMS))
    if keep_hits >= 1 or has_direct_supply_chain_signal(txt):
        return False
    hospitality_hits = count_any(txt, list(_COMMODITY_FOODSERVICE_HOSPITALITY_TERMS))
    food_hits = count_any(txt, list(_COMMODITY_FOODSERVICE_FOOD_TERMS))
    title_hits = count_any(ttl, list(_COMMODITY_FOODSERVICE_HOSPITALITY_TERMS))
    return (title_hits >= 1 and hospitality_hits >= 2 and food_hits >= 1) or (hospitality_hits >= 3 and food_hits >= 2)


def _managed_commodity_focus_metrics(
    item: dict[str, Any],
    title: str,
    desc: str,
    topic: str = "",
) -> dict[str, Any]:
    key = str(item.get("key") or "").strip()
    title_l = _nfkc_lower(title or "")
    desc_l = _nfkc_lower(desc or "")
    text_l = f"{title_l} {desc_l}".strip()
    compact_title_l = _compact_match_text(title or "")
    compact_text_l = _compact_match_text(f"{title or ''} {desc or ''}")
    empty = {
        "focus_score": 0.0,
        "title_primary_hits": 0,
        "title_context_hits": 0,
        "body_primary_hits": 0,
        "body_context_hits": 0,
        "pattern_hits": 0,
        "agri_anchor_hits": 0,
        "market_anchor_hits": 0,
        "issue_anchor_hits": 0,
        "consumer_noise_hits": 0,
        "matched": False,
        "topic_hit": False,
    }
    if not text_l or not key:
        return empty

    if key == "green_onion" and is_green_onion_sports_homonym_context(title, desc):
        return empty

    if is_commodity_corporate_stock_context(title, desc):
        return empty
    if key == "carrot" and "당근" in text_l and not is_edible_carrot_context(text_l):
        return empty
    if key == "potato" and "감자" in text_l and not is_fresh_potato_context(text_l):
        return empty
    if key == "eggplant" and "가지" in text_l and not is_edible_eggplant_context(text_l):
        return empty
    if key == "napa_cabbage" and "양배추" in text_l and re.search(r"(?<!양)배추", text_l) is None:
        return empty
    if key == "tomato" and "토마토" in text_l and not is_edible_tomato_context(text_l):
        return empty
    if key == "muskmelon" and "멜론" in text_l and not is_edible_melon_context(text_l):
        return empty
    if key == "apple" and "사과" in text_l and not is_edible_apple_context(text_l):
        return empty

    base_terms = _managed_commodity_base_terms(item, limit=6)
    context_terms = _ordered_unique_terms(item.get("context_terms") or [])
    registry_topics = [str(v or "").strip() for v in (item.get("registry_topics") or []) if str(v or "").strip()]
    topic_hit = bool(topic and topic in registry_topics)

    title_primary_hits = _commodity_board_term_hits(title_l, base_terms)
    title_pattern_hits = sum(
        1
        for pattern in _MANAGED_COMMODITY_CONTEXT_PATTERNS.get(key, [])
        if pattern.search(title_l)
    )
    # 한 글자 품목(배 등)은 일반 term matcher에서 의도적으로 제외된다.
    # 품목별 안전 맥락 패턴이 제목에서 직접 확인되면 대표기사의 title focus로 인정한다.
    if title_primary_hits == 0 and title_pattern_hits > 0:
        title_primary_hits = 1
    title_context_hits = _commodity_board_term_hits(title_l, context_terms)
    body_primary_hits = _commodity_board_term_hits(text_l, base_terms)
    body_context_hits = _commodity_board_term_hits(text_l, context_terms)
    pattern_hits = sum(1 for pattern in _MANAGED_COMMODITY_CONTEXT_PATTERNS.get(key, []) if pattern.search(text_l))
    agri_anchor_hits = count_any(text_l, list(_MANAGED_COMMODITY_FOCUS_AGRI_TERMS))
    market_anchor_hits = count_any(text_l, list(_MANAGED_COMMODITY_FOCUS_MARKET_TERMS))
    issue_anchor_hits = count_any(text_l, list(_MANAGED_COMMODITY_FOCUS_ISSUE_TERMS))
    processed_noise_hits = count_any(text_l, list(_MANAGED_COMMODITY_PROCESSED_NOISE_TERMS))
    lifestyle_noise_hits = count_any(text_l, list(_MANAGED_COMMODITY_LIFESTYLE_NOISE_TERMS))
    consumer_noise_hits = processed_noise_hits + lifestyle_noise_hits

    if key == "potato" and (
        count_any(title_l, list(_POTATO_PROCESSED_MARKERS)) >= 1
        or _contains_compact_marker(compact_title_l, list(_POTATO_PROCESSED_MARKERS))
    ):
        return empty
    if key == "eggplant" and (
        any(marker.lower() in title_l for marker in _EGGPLANT_NON_EDIBLE_MARKERS)
        or (_EGGPLANT_NON_EDIBLE_RX.search(title_l) is not None)
        or _contains_compact_marker(compact_title_l, list(_EGGPLANT_NON_EDIBLE_MARKERS))
    ):
        return empty
    if key == "tomato" and not is_edible_tomato_context(text_l):
        return empty
    if (
        title_primary_hits == 0
        and title_context_hits == 0
        and pattern_hits == 0
        and market_anchor_hits == 0
        and (
            processed_noise_hits >= 1
            or lifestyle_noise_hits >= 1
            or is_general_consumer_price_noise(text_l)
            or is_fruit_foodservice_event_context(text_l)
        )
    ):
        return empty

    score = (
        (title_primary_hits * 3.2)
        + (title_context_hits * 2.4)
        + (body_primary_hits * 1.4)
        + (body_context_hits * 0.9)
        + (pattern_hits * 2.6)
        + min(1.4, 0.22 * agri_anchor_hits)
        + min(1.8, 0.34 * market_anchor_hits)
        + min(1.6, 0.24 * issue_anchor_hits)
        + (0.5 if topic_hit and (title_primary_hits or body_primary_hits or pattern_hits) else 0.0)
    )

    if (
        title_primary_hits == 0
        and title_context_hits == 0
        and pattern_hits == 0
        and body_primary_hits <= 1
        and body_context_hits == 0
        and agri_anchor_hits == 0
        and market_anchor_hits == 0
        and issue_anchor_hits == 0
    ):
        score -= 2.8

    if processed_noise_hits and market_anchor_hits == 0 and issue_anchor_hits <= 1:
        score -= min(4.2, 1.35 * processed_noise_hits)
    if lifestyle_noise_hits and market_anchor_hits == 0 and issue_anchor_hits <= 1:
        score -= min(4.2, 1.15 * lifestyle_noise_hits)

    if is_fastfood_price_context(text_l) and market_anchor_hits == 0:
        score -= 3.2
    if is_general_consumer_price_noise(text_l) and market_anchor_hits == 0:
        score -= 2.6
    if is_fruit_foodservice_event_context(text_l) and market_anchor_hits == 0:
        score -= 3.0
    if is_flower_novelty_noise_context(title, desc) and market_anchor_hits == 0:
        score -= 3.0
    # 화훼: 문화/예술/전시 맥락만 있고 원예 맥락 없으면 감점 (간송전형필, 갤러리 등)
    _FLOWER_CULTURE_NOISE = ("문화보국", "전형필", "간송", "미술관", "갤러리", "아트페어", "경매사", "소장품")
    if key == "flowers" and any(t in text_l for t in _FLOWER_CULTURE_NOISE) and market_anchor_hits == 0 and agri_anchor_hits == 0:
        score -= 4.5
    # 상추: 도시농업/텃밭 체험 맥락만 있고 수급 맥락 없으면 감점
    _LETTUCE_URBAN_NOISE = ("텃밭", "상자텃밭", "도시농업", "옥상농원", "베란다", "주말농장")
    if key == "lettuce" and any(t in text_l for t in _LETTUCE_URBAN_NOISE) and market_anchor_hits == 0:
        score -= 4.0
    if is_macro_trade_noise_context(text_l) and market_anchor_hits == 0 and agri_anchor_hits <= 1:
        score -= 2.6

    direct_focus_hits = title_primary_hits + title_context_hits + pattern_hits
    exact_or_context_hits = direct_focus_hits + body_primary_hits + body_context_hits
    matched = bool(score >= _MANAGED_COMMODITY_FOCUS_MATCH_MIN and exact_or_context_hits > 0)
    if direct_focus_hits == 0 and market_anchor_hits == 0 and issue_anchor_hits == 0 and agri_anchor_hits < 2:
        matched = False
    if direct_focus_hits == 0 and market_anchor_hits == 0 and agri_anchor_hits == 0:
        matched = False
    if processed_noise_hits and direct_focus_hits == 0 and market_anchor_hits == 0:
        matched = False
    if key == "potato" and _contains_compact_marker(compact_text_l, list(_POTATO_PROCESSED_MARKERS)):
        matched = False
    if key == "eggplant" and _contains_compact_marker(compact_text_l, list(_EGGPLANT_NON_EDIBLE_MARKERS)):
        matched = False
    # 포도: 와인/경매/빈티지 기사는 원예 수급과 무관 (가공품/라이프스타일)
    if key == "grape":
        _GRAPE_WINE_KWS = ("와인", "wine", "소믈리에", "빈티지", "양조장", "와이너리", "winery",
                           "낙찰", "경매 낙찰", "옥션", "auction", "로마네", "콩티", "샤토")
        _grape_wine_hits = sum(1 for w in _GRAPE_WINE_KWS if w in text_l)
        _grape_supply_kws = ("출하", "수급", "도매", "경락", "산지", "농가", "재배", "작황", "수확", "가격")
        _grape_supply_hits = sum(1 for w in _grape_supply_kws if w in text_l)
        if _grape_wine_hits >= 1 and _grape_supply_hits < 2:
            matched = False

    return {
        "focus_score": round(float(score), 4),
        "title_primary_hits": title_primary_hits,
        "title_pattern_hits": title_pattern_hits,
        "title_context_hits": title_context_hits,
        "body_primary_hits": body_primary_hits,
        "body_context_hits": body_context_hits,
        "pattern_hits": pattern_hits,
        "agri_anchor_hits": agri_anchor_hits,
        "market_anchor_hits": market_anchor_hits,
        "issue_anchor_hits": issue_anchor_hits,
        "consumer_noise_hits": consumer_noise_hits,
        "matched": matched,
        "topic_hit": topic_hit,
    }


def _managed_commodity_focus_summary(title: str, desc: str, topic: str = "") -> dict[str, Any]:
    matches: list[tuple[str, dict[str, Any], dict[str, Any]]] = []
    for item in MANAGED_COMMODITY_CATALOG:
        key = str(item.get("key") or "").strip()
        if not key:
            continue
        metrics = _managed_commodity_focus_metrics(item, title, desc, topic)
        if not metrics.get("matched"):
            continue
        matches.append((key, item, metrics))

    matches.sort(
        key=lambda entry: (
            float(entry[2].get("focus_score") or 0.0),
            1 if entry[1].get("program_core") else 0,
            -int(entry[1].get("order") or 0),
        ),
        reverse=True,
    )
    keys = [entry[0] for entry in matches]
    focus_by_key = {
        entry[0]: float(entry[2].get("focus_score") or 0.0)
        for entry in matches
    }
    strong_keys = [
        entry[0]
        for entry in matches
        if float(entry[2].get("focus_score") or 0.0) >= _MANAGED_COMMODITY_FOCUS_STRONG_MIN
    ]
    program_core_keys = [entry[0] for entry in matches if bool(entry[1].get("program_core"))]
    program_core_strong_keys = [
        entry[0]
        for entry in matches
        if bool(entry[1].get("program_core"))
        and float(entry[2].get("focus_score") or 0.0) >= _MANAGED_COMMODITY_FOCUS_STRONG_MIN
    ]
    max_focus_score = max(focus_by_key.values()) if focus_by_key else 0.0
    return {
        "keys": keys,
        "count": len(keys),
        "focus_by_key": focus_by_key,
        "strong_keys": strong_keys,
        "strong_count": len(strong_keys),
        "program_core_keys": program_core_keys,
        "program_core_count": len(program_core_keys),
        "program_core_strong_keys": program_core_strong_keys,
        "program_core_strong_count": len(program_core_strong_keys),
        "max_focus_score": float(max_focus_score),
    }


def _managed_commodity_focus_summary_for_article(article: "Article") -> dict[str, Any]:
    cached = getattr(article, "_managed_focus_summary", None)
    if isinstance(cached, dict):
        return cached
    summary = _managed_commodity_focus_summary(
        getattr(article, "title", "") or "",
        getattr(article, "description", "") or "",
        getattr(article, "topic", "") or "",
    )
    setattr(article, "_managed_focus_summary", summary)
    return summary


def managed_commodity_focus_keys_for_text(
    title: str,
    desc: str,
    topic: str = "",
    max_keys: int | None = None,
) -> list[str]:
    summary = _managed_commodity_focus_summary(title, desc, topic)
    keys = list(summary.get("keys") or [])
    if not keys:
        return []
    if max_keys is None or max_keys <= 0 or len(keys) <= 1:
        return keys if max_keys is None else keys[:max_keys]
    focus_by_key = dict(summary.get("focus_by_key") or {})
    lead_key = keys[0]
    lead_score = float(focus_by_key.get(lead_key) or 0.0)
    selected = [lead_key]
    for key in keys[1:]:
        if len(selected) >= max_keys:
            break
        focus_score = float(focus_by_key.get(key) or 0.0)
        if focus_score >= max(_MANAGED_COMMODITY_FOCUS_MATCH_MIN + 0.9, lead_score - 0.9):
            selected.append(key)
    return selected


def managed_commodity_focus_keys_for_article(
    article: "Article",
    max_keys: int | None = None,
) -> list[str]:
    summary = _managed_commodity_focus_summary_for_article(article)
    keys = list(summary.get("keys") or [])
    if not keys:
        return []
    if max_keys is None or max_keys <= 0 or len(keys) <= 1:
        return keys if max_keys is None else keys[:max_keys]
    focus_by_key = dict(summary.get("focus_by_key") or {})
    lead_key = keys[0]
    lead_score = float(focus_by_key.get(lead_key) or 0.0)
    selected = [lead_key]
    for key in keys[1:]:
        if len(selected) >= max_keys:
            break
        focus_score = float(focus_by_key.get(key) or 0.0)
        if focus_score >= max(_MANAGED_COMMODITY_FOCUS_MATCH_MIN + 0.9, lead_score - 0.9):
            selected.append(key)
    return selected


def _managed_commodity_board_focus_metrics(item: dict[str, Any], article: "Article") -> dict[str, Any]:
    metrics = dict(
        _managed_commodity_focus_metrics(
            item,
            getattr(article, "title", "") or "",
            getattr(article, "description", "") or "",
            getattr(article, "topic", "") or "",
        )
    )
    metrics["board_eligible"] = False
    metrics["board_penalty"] = 0.0
    if not metrics.get("matched"):
        return metrics

    title = str(getattr(article, "title", "") or "")
    desc = str(getattr(article, "description", "") or "")
    text = f"{title} {desc}".strip()
    text_l = _nfkc_lower(text)
    title_l = _nfkc_lower(title)
    desc_l = _nfkc_lower(desc)
    host_l = normalize_host(getattr(article, "domain", "") or "")
    press_l = _nfkc_lower(str(getattr(article, "press", "") or ""))
    key = str(item.get("key") or "").strip()
    title_focus_hits = int(metrics.get("title_primary_hits") or 0) + int(metrics.get("title_context_hits") or 0) + int(metrics.get("pattern_hits") or 0)
    body_focus_hits = int(metrics.get("body_primary_hits") or 0) + int(metrics.get("body_context_hits") or 0)
    agri_anchor_hits = int(metrics.get("agri_anchor_hits") or 0)
    market_anchor_hits = int(metrics.get("market_anchor_hits") or 0)
    issue_anchor_hits = int(metrics.get("issue_anchor_hits") or 0)
    focus_score = float(metrics.get("focus_score") or 0.0)

    if is_commodity_corporate_stock_context(title, desc):
        return metrics
    if is_commodity_foodservice_lifestyle_context(title, desc):
        return metrics
    if key == "potato" and not is_fresh_potato_context(text_l):
        return metrics
    if key == "eggplant" and not is_edible_eggplant_context(text_l):
        return metrics
    if key == "napa_cabbage" and "양배추" in text_l and re.search(r"(?<!양)배추", text_l) is None:
        return metrics
    if key == "tomato" and not is_edible_tomato_context(text_l):
        return metrics
    if key == "tomato" and any(
        marker in candidate
        for marker in ("[ib 토마토", "ib 토마토", "뉴스토마토", "newstomato")
        for candidate in (title_l, desc_l, host_l, press_l)
    ):
        return metrics
    if key in _FRUIT_TREE_COMMODITY_KEYS and is_fruit_blossom_tourism_context(title, desc):
        return metrics
    # 해외 축산 기사: 제목에 품목명이 부수적으로 등장해도 해당 품목 보드에 연결하지 않음
    if _is_overseas_livestock_story(title, desc):
        return metrics
    # 지자체 행정 컨설팅/기술지도: 수급 기사가 아닌 행정 서비스
    if _is_admin_consulting_story(title, desc):
        return metrics
    # 로컬 브랜딩/스포츠 이벤트: 농산물 수급과 무관
    if _is_local_branding_event_story(title, desc):
        return metrics

    body_operational_match = bool(
        title_focus_hits == 0
        and body_focus_hits >= 1
        and not is_commodity_broad_price_roundup_context(title, desc)
        and (
            has_direct_supply_chain_signal(text_l)
            or market_anchor_hits >= 1
            or issue_anchor_hits >= 1
        )
    )
    body_direct_focus_match = bool(
        title_focus_hits == 0
        and body_focus_hits >= 1
        and focus_score >= _MANAGED_COMMODITY_FOCUS_STRONG_MIN
        and not is_commodity_broad_price_roundup_context(title, desc)
        and (
            has_direct_supply_chain_signal(text_l)
            or market_anchor_hits >= 1
            or (issue_anchor_hits >= 2 and agri_anchor_hits >= 1)
        )
    )
    body_policy_roundup_match = bool(
        item.get("program_core")
        and title_focus_hits == 0
        and body_focus_hits >= 1
        and (
            is_supply_stabilization_policy_context(text_l)
            or is_policy_market_brief_context(text_l)
        )
    )
    if body_policy_roundup_match:
        return metrics
    if title_focus_hits == 0 and not (body_operational_match or body_direct_focus_match):
        return metrics

    if is_general_consumer_price_noise(text_l) and title_focus_hits == 0:
        return metrics
    if is_fastfood_price_context(text_l):
        return metrics
    if is_macro_trade_noise_context(text_l) and title_focus_hits == 0 and market_anchor_hits == 0:
        return metrics
    if is_retail_promo_context(text_l) and title_focus_hits == 0 and market_anchor_hits == 0:
        return metrics

    board_penalty = 0.0
    if is_local_agri_org_feature_context(title, desc) and market_anchor_hits == 0 and focus_score < (_MANAGED_COMMODITY_FOCUS_STRONG_MIN + 1.0):
        board_penalty += 12.0
    if any(term in title_l for term in _MANAGED_COMMODITY_BOARD_EVENT_TITLE_TERMS) and market_anchor_hits == 0:
        board_penalty += 6.0
    if is_retail_promo_context(text_l):
        board_penalty += 8.0
    if str(getattr(article, "section", "") or "").strip() == "supply" and is_supply_tourism_event_context(title, desc):
        board_penalty += 10.0
    if is_commodity_sales_promo_context(title, desc):
        board_penalty += 10.0
    if is_commodity_political_statement_context(title, desc):
        board_penalty += 10.0
    if is_commodity_support_advice_context(title, desc):
        board_penalty += 10.0
    if is_commodity_consumer_guide_context(title, desc):
        board_penalty += 12.0
    if is_commodity_regional_branding_context(title, desc):
        board_penalty += 12.0
    if is_commodity_broad_price_roundup_context(title, desc):
        board_penalty += 12.0

    metrics["board_eligible"] = True
    metrics["board_penalty"] = round(float(board_penalty), 3)
    return metrics


def _managed_commodity_board_focus_metrics_for_article(article: "Article", item: dict[str, Any]) -> dict[str, Any]:
    key = str(item.get("key") or "").strip()
    cache = getattr(article, "_managed_board_focus_metrics", None)
    if not isinstance(cache, dict):
        cache = {}
    cached = cache.get(key)
    if isinstance(cached, dict):
        return cached
    metrics = _managed_commodity_board_focus_metrics(item, article)
    cache[key] = metrics
    setattr(article, "_managed_board_focus_metrics", cache)
    return metrics


def _managed_article_significance_metrics(
    article: "Article",
    *,
    program_core: bool = False,
    focus_metrics: dict[str, Any] | None = None,
) -> dict[str, Any]:
    title = str(getattr(article, "title", "") or "")
    desc = str(getattr(article, "description", "") or "")
    title_l = _nfkc_lower(title)
    text_l = _nfkc_lower(f"{title} {desc}".strip())
    dom = normalize_host(getattr(article, "domain", "") or "")
    press = str(getattr(article, "press", "") or "").strip()
    issue_bucket = supply_issue_context_bucket(title, desc)
    feature_kind = supply_feature_context_kind(title, desc)
    market_response = is_dist_field_market_response_context(title, desc, dom, press)
    direct_supply = has_direct_supply_chain_signal(text_l)
    supply_tourism = is_supply_tourism_event_context(title, desc)
    fruit_blossom_tourism = is_fruit_blossom_tourism_context(title, desc)
    market_anchor_hits = int((focus_metrics or {}).get("market_anchor_hits") or 0)
    issue_anchor_hits = int((focus_metrics or {}).get("issue_anchor_hits") or 0)
    focus_score = float((focus_metrics or {}).get("focus_score") or 0.0)
    issue_title_hits = count_any(title_l, [w.lower() for w in _MANAGED_COMMODITY_BOARD_STRONG_ISSUE_TITLE_TERMS])
    training_title_hits = count_any(title_l, [w.lower() for w in _MANAGED_COMMODITY_BOARD_TRAINING_TITLE_TERMS])
    profile_title_hits = count_any(title_l, [w.lower() for w in _MANAGED_COMMODITY_BOARD_PROFILE_TITLE_TERMS])
    consumer_noise_hits = count_any(
        text_l,
        [
            w.lower()
            for w in (
                "관광",
                "여행",
                "나들이",
                "축제",
                "포토존",
                "인생샷",
                "맛집",
                "드라이브",
                "고택",
                "메타세쿼이아",
                "꽃길",
                "꽃 필 무렵",
                "최고의 시간",
            )
        ],
    )
    story_bonus = 0.0
    story_penalty = 0.0

    if issue_bucket == "commodity_issue":
        story_bonus += 34.0
    elif issue_bucket == "farm_action":
        story_bonus += 28.0
    elif issue_bucket == "export_recovery":
        story_bonus += 24.0
    elif feature_kind == "field":
        story_bonus += 12.0
    elif feature_kind == "quality":
        story_bonus += 8.0
    elif feature_kind == "issue":
        story_bonus += 10.0

    if market_response:
        story_bonus += 12.0
    if direct_supply:
        story_bonus += 7.0
    story_bonus += min(12.0, issue_title_hits * 2.6)
    if market_anchor_hits >= 1:
        story_bonus += min(6.0, market_anchor_hits * 2.0)
    if issue_anchor_hits >= 2:
        story_bonus += min(6.0, issue_anchor_hits * 1.2)
    if program_core and (issue_bucket or feature_kind == "field" or feature_kind == "quality"):
        story_bonus += 4.0

    if is_supply_weak_tail_context(title, desc):
        story_penalty += 14.0
    if is_local_agri_org_feature_context(title, desc):
        story_penalty += 20.0
    if is_supply_org_promo_feature_context(title, desc):
        story_penalty += 18.0
    if training_title_hits >= 1 and issue_bucket is None and (not market_response) and market_anchor_hits == 0:
        story_penalty += 22.0
    if (
        profile_title_hits >= 1
        and issue_bucket is None
        and feature_kind is None
        and (not market_response)
        and market_anchor_hits == 0
        and issue_title_hits == 0
    ):
        story_penalty += 24.0
    if (
        any(term.lower() in title_l for term in _MANAGED_COMMODITY_BOARD_EVENT_TITLE_TERMS)
        and issue_title_hits == 0
        and market_anchor_hits == 0
        and issue_anchor_hits <= 1
    ):
        story_penalty += 12.0
    if (
        focus_score < _MANAGED_COMMODITY_FOCUS_STRONG_MIN
        and issue_bucket is None
        and feature_kind is None
        and (not market_response)
        and issue_title_hits == 0
        and market_anchor_hits == 0
    ):
        story_penalty += 8.0
    if (
        feature_kind == "field"
        and issue_bucket is None
        and (not direct_supply)
        and (not market_response)
        and issue_title_hits == 0
        and market_anchor_hits == 0
    ):
        story_penalty += 10.0
    if supply_tourism:
        story_penalty += 18.0
    if fruit_blossom_tourism:
        story_penalty += 26.0
    if consumer_noise_hits >= 2 and issue_bucket is None and (not direct_supply) and (not market_response):
        story_penalty += 16.0
    if is_commodity_sales_promo_context(title, desc):
        story_penalty += 18.0
    if is_commodity_political_statement_context(title, desc):
        story_penalty += 18.0
    if is_commodity_support_advice_context(title, desc):
        story_penalty += 20.0
    if is_commodity_consumer_guide_context(title, desc):
        story_penalty += 18.0
    if is_commodity_regional_branding_context(title, desc):
        story_penalty += 18.0
    if is_commodity_broad_price_roundup_context(title, desc):
        story_penalty += 20.0

    return {
        "issue_bucket": issue_bucket or "",
        "feature_kind": feature_kind or "",
        "market_response": bool(market_response),
        "direct_supply": bool(direct_supply),
        "supply_tourism": bool(supply_tourism),
        "fruit_blossom_tourism": bool(fruit_blossom_tourism),
        "market_anchor_hits": int(market_anchor_hits),
        "issue_anchor_hits": int(issue_anchor_hits),
        "issue_title_hits": int(issue_title_hits),
        "training_title_hits": int(training_title_hits),
        "profile_title_hits": int(profile_title_hits),
        "consumer_noise_hits": int(consumer_noise_hits),
        "story_bonus": round(float(story_bonus), 3),
        "story_penalty": round(float(story_penalty), 3),
        "priority_score": round(float(story_bonus - story_penalty), 3),
    }


def managed_commodity_board_keys_for_article(
    article: "Article",
    max_keys: int | None = None,
) -> list[str]:
    keys = list(managed_commodity_focus_keys_for_article(article))
    if not keys:
        return []
    selected: list[str] = []
    for key in keys:
        item = MANAGED_COMMODITY_BY_KEY.get(key)
        if item is None:
            continue
        metrics = _managed_commodity_board_focus_metrics_for_article(article, item)
        if metrics.get("board_eligible"):
            selected.append(key)
    if max_keys is None or max_keys <= 0:
        return selected
    return selected[:max_keys]


@lru_cache(maxsize=16384)
def _managed_commodity_keys_for_text_cached(title: str, desc: str, topic: str = "") -> tuple[str, ...]:
    txt = f"{title or ''} {desc or ''}".lower()
    topic_name = str(topic or "").strip()
    matched: list[str] = []

    for item in MANAGED_COMMODITY_CATALOG:
        key = str(item.get("key") or "").strip()
        if not key or key in matched:
            continue
        if _managed_commodity_matches_text(item, txt, topic_name):
            matched.append(key)
    return tuple(matched)


def managed_commodity_keys_for_text(title: str, desc: str, topic: str = "") -> list[str]:
    return list(_managed_commodity_keys_for_text_cached(str(title or ""), str(desc or ""), str(topic or "")))


def managed_commodity_keys_for_article(article: "Article") -> list[str]:
    return managed_commodity_keys_for_text(
        getattr(article, "title", "") or "",
        getattr(article, "description", "") or "",
        getattr(article, "topic", "") or "",
    )


def _managed_commodity_match_summary(title: str, desc: str, topic: str = "") -> dict[str, Any]:
    keys = managed_commodity_keys_for_text(title, desc, topic)
    program_core_keys = [
        key
        for key in keys
        if bool((MANAGED_COMMODITY_BY_KEY.get(key) or {}).get("program_core"))
    ]
    return {
        "keys": keys,
        "count": len(keys),
        "program_core_keys": program_core_keys,
        "program_core_count": len(program_core_keys),
        "has_program_core": bool(program_core_keys),
    }


@lru_cache(maxsize=4096)
def _managed_commodity_item_for_seed(seed: str) -> dict[str, Any] | None:
    seed_s = str(seed or "").strip()
    if not seed_s:
        return None
    seed_l = seed_s.lower()
    for item in MANAGED_COMMODITY_CATALOG:
        exact_terms = _ordered_unique_terms(
            [
                item.get("short_label") or "",
                re.sub(r"\s*\([^)]*\)", "", str(item.get("label") or "")).strip(),
                item.get("label") or "",
            ]
            + list(item.get("match_terms") or [])
            + list(item.get("registry_topics") or [])
        )
        if seed_l in {str(term or "").strip().lower() for term in exact_terms if str(term or "").strip()}:
            return item
    rep = TOPIC_REP_BY_TERM_L.get(seed_s.lower(), seed_s)
    keys = managed_commodity_keys_for_text(seed_s, "", rep)
    if not keys:
        return None
    return MANAGED_COMMODITY_BY_KEY.get(keys[0])

@lru_cache(maxsize=8192)
def _topic_scores(title: str, desc: str) -> dict[str, float]:
    t = (title + " " + desc).lower()
    tl = (title or "").lower()
    scores: dict[str, float] = {}
    managed_focus_item_cache: dict[str, dict[str, Any] | None] = {}

    for topic, words in COMMODITY_TOPICS:
        sc = 0.0
        if topic == "가지" and not is_edible_eggplant_context(t):
            continue
        if topic == "멜론" and not is_edible_melon_context(t):
            # 멜론(음원 플랫폼) 오탐 방지
            continue

        if topic == "당근" and not is_edible_carrot_context(t):
            # 당근(플랫폼/앱) 동음이의어 오탐 방지
            continue

        if topic == "감자" and not is_fresh_potato_context(t):
            # 감튀/감자튀김 등 가공·외식 문맥 오탐 방지
            continue


        if topic == "피망" and not is_edible_pimang_context(t):
            # 피망(게임/브랜드) 오탐 방지
            continue

        if topic == "사과" and not is_edible_apple_context(t):
            # 사과(과일) 동음이의어(사과대/사과문 등) 오탐 방지
            continue

        if topic == "사과" and any(x in t for x in ("의사과학", "의사과학자", "의사과학원", "의사공학", "의과학", "의과학원")):
            # '의사과학자/의사과학원' 등은 '사과(apple)'가 아니라 의료/학문 용어(부분문자열) 오탐
            continue

        managed_item = managed_focus_item_cache.get(topic)
        if topic not in managed_focus_item_cache:
            managed_item = _managed_commodity_item_for_seed(topic)
            managed_focus_item_cache[topic] = managed_item
        if managed_item:
            focus_metrics = _managed_commodity_focus_metrics(managed_item, title, desc, topic)
            if not focus_metrics.get("matched"):
                continue


        # 기본(2글자 이상 키워드): 부분문자열 매칭
        for w in words:
            wl = (w or "").lower()
            if len(wl) < 2:
                continue
            if wl in t:
                sc += 1.0
                if wl in tl:
                    sc += 0.4

        # 1글자 키워드: 맥락 패턴으로만 보강
        # - topic 자체가 1글자 품목을 포함할 수 있어 topic명을 기반으로 패턴을 선택
        if topic == "배":
            if any(p.search(t) for p in _SINGLE_TERM_CONTEXT_PATTERNS["배"]):
                sc += 1.8
        if topic == "밤":
            if any(p.search(t) for p in _SINGLE_TERM_CONTEXT_PATTERNS["밤"]):
                sc += 1.6
        if topic == "화훼":
            if any(p.search(t) for p in _SINGLE_TERM_CONTEXT_PATTERNS["꽃"]):
                sc += 1.3
        if topic == "감귤/만감":
            if any(p.search(t) for p in _SINGLE_TERM_CONTEXT_PATTERNS["귤"]):
                sc += 1.1
        if topic == "쌀":
            if any(p.search(t) for p in _SINGLE_TERM_CONTEXT_PATTERNS["쌀"]):
                sc += 1.2

        if sc > 0:
            scores[topic] = sc
    # ✅ 정책 강신호(관세/통관/보세/할당관세/정부)면 '정책' 토픽 가중치 부여
    POLICY_STRONG_TERMS = (
        "관세", "할당관세", "무관세", "fta", "통관", "수입신고", "보세", "보세구역", "반출", "반입",
        "관세청", "기재부", "농식품부", "정부", "대책", "지원", "단속", "고시", "개정", "시행",
    )
    if any(x in t for x in POLICY_STRONG_TERMS):
        scores["정책"] = scores.get("정책", 0.0) + 4.5


    return scores

def best_topic_and_score(title: str, desc: str) -> tuple[str, float]:
    scores = _topic_scores(title, desc)
    if not scores:
        return "기타", 0.0
    # 최고 점수 topic, 동점이면 '품목(원예)'를 우선(정책/도매시장보다 앞서 표시)
    best_topic = None
    best_sc = -1.0
    for topic, sc in scores.items():
        if sc > best_sc:
            best_topic, best_sc = topic, sc
        elif sc == best_sc and best_topic is not None:
            if topic in _HORTI_TOPICS_SET and best_topic not in _HORTI_TOPICS_SET:
                best_topic = topic
    return best_topic or "기타", float(best_sc)

def best_horti_score(title: str, desc: str) -> float:
    scores = _topic_scores(title, desc)
    horti = [sc for t, sc in scores.items() if t in _HORTI_TOPICS_SET]
    best = max(horti) if horti else 0.0
    managed_summary = _managed_commodity_match_summary(title, desc)
    managed_count = int(managed_summary.get("count") or 0)
    program_core_count = int(managed_summary.get("program_core_count") or 0)
    if managed_count:
        best = max(best, 1.0 + (0.32 * managed_count) + (0.28 * program_core_count))
    title_managed_summary = _managed_commodity_match_summary(title, "")
    title_managed_count = int(title_managed_summary.get("count") or 0)
    title_program_core_count = int(title_managed_summary.get("program_core_count") or 0)
    if title_managed_count:
        best = max(best, 1.25 + (0.38 * title_managed_count) + (0.32 * title_program_core_count))
    return best

def extract_topic(title: str, desc: str) -> str:
    topic, _ = best_topic_and_score(title, desc)
    if topic not in _HORTI_TOPICS_SET:
        title_focus_summary = _managed_commodity_focus_summary(title, "", "")
        focus_summary = title_focus_summary if title_focus_summary.get("count") else _managed_commodity_focus_summary(title, desc, "")
        keys = list(focus_summary.get("strong_keys") or focus_summary.get("keys") or [])
        if keys and float(focus_summary.get("max_focus_score") or 0.0) >= _MANAGED_COMMODITY_FOCUS_MATCH_MIN:
            item = MANAGED_COMMODITY_BY_KEY.get(str(keys[0]) or "") or {}
            registry_topics = [str(v or "").strip() for v in (item.get("registry_topics") or []) if str(v or "").strip()]
            managed_topic = registry_topics[0] if registry_topics else str(item.get("short_label") or item.get("label") or "").strip()
            if managed_topic:
                return managed_topic
    return topic

def make_norm_key(canon_url: str, press: str, title_key: str) -> str:
    if canon_url:
        h = hashlib.sha256(canon_url.encode("utf-8")).hexdigest()[:32]
        return f"url:{h}"
    base = f"{(press or '').strip()}|{title_key}"
    h = hashlib.sha256(base.encode("utf-8")).hexdigest()[:32]
    return f"pt:{h}"

def has_any(text: str, words: list[str] | tuple[str, ...] | set[str]) -> bool:
    return any(w in text for w in words)

def count_any(text: str, words: list[str] | tuple[str, ...] | set[str]) -> int:
    return sum(1 for w in words if w in text)


def has_apc_agri_context(text: str) -> bool:
    """APC 오탐(UPS/전원장비 등)을 막기 위해, '농업/산지유통' 문맥일 때만 APC로 인정."""
    t = (text or "").lower()
    if "apc" not in t:
        return False

    # strong: APC와 함께 나오면 거의 농산물 산지유통 문맥으로 볼 수 있는 신호
    strong_hints = (
        "산지유통", "산지유통센터", "농산물산지유통센터",
        "선별", "선별장", "선과", "선과장", "집하", "집하장",
        "저온", "저온저장", "저장고", "ca저장",
        "가락시장", "도매시장", "공판장", "경락", "경매", "반입",
        "농협", "조합", "출하", "출하량",
        "원예", "과수", "청과", "농산물", "과일", "채소", "화훼",
    )
    # weak: 단독으로는 약하지만 APC와 함께 2개 이상이면 농업 현장 맥락일 가능성이 높음
    weak_hints = (
        "유통", "물류", "저장", "선별기", "비파괴", "공선", "공동선별",
        "산지", "생산자", "농가", "작목반", "조합원",
    )

    strong_hit = count_any(t, [h.lower() for h in strong_hints])
    weak_hit = count_any(t, [h.lower() for h in weak_hints])

    if strong_hit >= 1:
        return True
    return weak_hit >= 2

# -----------------------------
# Melon safety guards
# - '멜론'은 음원 플랫폼(멜론)과 동음이의어라 오탐이 잦다.
# - '먹는 멜론' 맥락(재배/출하/작황/농가/도매시장 등)일 때만 품목으로 인정한다.
# -----------------------------
_MELON_MUSIC_MARKERS = [
    "멜론차트", "음원", "스트리밍", "뮤직", "앨범", "가수", "노래", "신곡",
    "top100", "top 100", "멜론티켓", "콘서트", "공연", "팬미팅", "이용권",
    "카카오엔터", "카카오 엔터", "멜론앱", "멜론 앱", "멜론 서비스",
]
_MELON_EDIBLE_MARKERS = [
    "과일", "과채", "시설", "하우스", "비가림", "재배", "농가", "작황", "수확", "출하",
    "도매", "도매가격", "가락시장", "도매시장", "공판장", "경락", "경매", "반입",
    "산지", "산지유통", "산지유통센터", "apc", "선별", "저온", "저장", "ca저장",
    "수급", "시세", "수출", "검역", "통관", "잔류농약",
]
_MELON_VARIETY_MARKERS = [
    "머스크멜론", "네트멜론", "얼스멜론", "하미과", "칸탈루프", "허니듀",
]

def is_edible_melon_context(text: str) -> bool:
    """Return True only when '멜론' clearly means the edible fruit (not the music service).

    Heuristics:
      - Always accept if a melon variety marker is present (머스크멜론 등)
      - If strong music/entertainment markers exist (멜론차트/음원/앨범 등),
        require *strong* edible markers; otherwise reject.
      - Accept edible context when at least one agri/produce marker exists OR
        when '멜론 값/가격/시세/도매가격' 같은 가격 패턴이 나타나고 음악마커가 없을 때.
    """
    t = (text or "").lower()
    if "멜론" not in t:
        return False

    # 품종/유형이 명시되면 거의 100% 과일
    if any(v.lower() in t for v in _MELON_VARIETY_MARKERS):
        return True

    music_hit = any(w.lower() in t for w in _MELON_MUSIC_MARKERS)

    # 농업/유통/품질 신호(가격 단어 단독은 제외)
    edible_hit = any(w.lower() in t for w in _MELON_EDIBLE_MARKERS)

    # 가격 패턴(멜론 값/가격/시세/도매가격 등)이 있으면, 음악마커가 없을 때만 과일로 인정
    price_pat = bool(re.search(r"멜론\s*(값|가격|시세|도매가격|출하가|경락가)", t))
    if price_pat and not music_hit:
        edible_hit = True

    # 음악/엔터 맥락이 강한데 먹는 멜론 신호가 없으면 오탐으로 판단
    if music_hit and not edible_hit:
        return False

    return edible_hit

# -----------------------------
# Pimang safety guards
# - '피망'은 게임/브랜드(피망/pmang/뉴맞고 등)로도 매우 자주 등장한다.
# - 채소(피망/파프리카) 맥락이 확실할 때만 품목으로 인정한다.
# -----------------------------
_PIMANG_GAME_MARKERS = [
    "pmang", "피망게임", "뉴맞고", "맞고", "고스톱", "고포류", "포커", "네오위즈", "게임", "보드게임", "모바일게임",
    "팝업", "스타필드", "코엑스", "이벤트", "출시", "업데이트",
]
_PIMANG_EDIBLE_MARKERS = [
    "채소", "과채", "파프리카", "피망(채소)", "농산물", "원예", "재배", "농가", "작황", "수확", "출하",
    "도매", "도매가격", "가락시장", "도매시장", "공판장", "경락", "경매", "반입",
    "산지", "산지유통", "산지유통센터", "apc", "선별", "저온", "저장", "ca저장",
    "수급", "시세", "가격", "수출", "검역", "통관",
]

def is_edible_pimang_context(text: str) -> bool:
    """Return True only when '피망' clearly refers to the edible vegetable (bell pepper).

    - If '파프리카/채소/농산물/재배/출하/도매시장' 등 식품/농업 마커가 있으면 통과.
    - 게임/엔터 마커가 강한데 식품 마커가 없으면 오탐으로 차단.
    - '피망 가격/시세/도매가격/출하' 패턴은 게임 마커가 없을 때만 식품으로 인정.
    """
    t = (text or "").lower()
    if "피망" not in t:
        return False

    edible_hit = any(w.lower() in t for w in _PIMANG_EDIBLE_MARKERS)
    game_hit = any(w.lower() in t for w in _PIMANG_GAME_MARKERS)

    price_pat = bool(re.search(r"피망\s*(값|가격|시세|도매가격|출하가|경락가)", t))
    if price_pat and not game_hit:
        edible_hit = True

    if game_hit and not edible_hit:
        return False

    return edible_hit


