def is_policy_legislative_reform_context(title: str, desc: str, dom: str = "", press: str = "") -> bool:
    """Agriculture-law reform stories are policy issues, not low-value campaign noise."""
    if is_policy_price_stabilization_system_context(title, desc, dom, press):
        return False
    ttl = title or ""
    txt = _nfkc_lower(f"{ttl} {desc or ''}".strip())
    ttl_l = _nfkc_lower(ttl)
    if not txt:
        return False
    law_hits = count_any(txt, [w.lower() for w in _POLICY_LEGISLATIVE_LAW_TERMS])
    action_hits = count_any(txt, [w.lower() for w in _POLICY_LEGISLATIVE_ACTION_TERMS])
    agri_hits = count_any(txt, [w.lower() for w in _POLICY_LEGISLATIVE_AGRI_TERMS])
    title_hits = count_any(
        ttl_l,
        [w.lower() for w in ("입법", "농협법", "농지법", "농안법", "개정", "법안", "농업민생")],
    )
    if law_hits >= 1 and action_hits >= 1 and agri_hits >= 1:
        return True
    return title_hits >= 2 and agri_hits >= 1


def _is_agri_supplier_payment_gap_text(title: str, desc: str) -> bool:
    """Retailer settlement delays that directly affect farm suppliers are policy-relevant."""
    ttl_l = _nfkc_lower(title or "")
    text = _nfkc_lower(f"{title or ''} {desc or ''}")
    if not text.strip():
        return False
    retail_actor_hits = count_any(
        text,
        [w.lower() for w in ("홈플러스", "대형마트", "마트", "유통업체", "유통 업체", "납품업체", "협력업체")],
    )
    payment_hits = count_any(
        text,
        [w.lower() for w in ("미정산", "납품대금", "납품 대금", "정산 지연", "대금 정산", "회생")],
    )
    agri_supplier_hits = count_any(
        text,
        [w.lower() for w in ("농산물", "농가", "농업인", "산지", "납품업체", "협력업체", "납품 업체", "농산물 협력업체")],
    )
    impact_hits = count_any(
        text,
        [w.lower() for w in ("생존 위기", "피해", "부담", "대책", "호소", "확대", "정산 지연")],
    )
    title_signal = count_any(
        ttl_l,
        [w.lower() for w in ("미정산", "납품대금", "납품 대금", "정산 지연", "회생", "농산물", "농가")],
    )
    return (
        retail_actor_hits >= 1
        and payment_hits >= 1
        and agri_supplier_hits >= 2
        and impact_hits >= 1
        and title_signal >= 2
    )


def is_low_value_local_political_context(title: str, desc: str) -> bool:
    """선거·공약·지역 정치 발언 중심의 농업 부분언급 기사를 낮은 가치로 본다."""
    if is_policy_legislative_reform_context(title, desc):
        return False
    if _is_agri_supplier_payment_gap_text(title, desc):
        return False
    title_l = _nfkc_lower(title or "")
    text = _nfkc_lower(f"{title or ''} {desc or ''}")
    campaign_terms = (
        "후보", "예비후보", "지방선거", "선거", "출마", "공약", "민생투어",
        "정책 간담회", "정책간담회", "보수 결집", "대도약", "혁명 선언", "선언",
        "끌어올리겠다", "키우겠다", "만들겠다", "약속했다",
    )
    hard_campaign_terms = ("예비후보", " 후보", "후보 ", "후보는", "후보가", "후보,", "지방선거", "선거", "출마", "공약", "민생투어", "보수 결집")
    office_terms = ("도지사", "시장", "군수", "도의원", "시의원", "국회의원", "위원장", "정당", "국민의힘", "더불어민주당")
    direct_field_supply_title = (
        best_horti_score(title or "", "") >= 1.2
        and count_any(
            title_l,
            [w.lower() for w in ("소비 부진", "수확", "수확철", "가격", "수급", "작황", "도매", "생산", "하락", "폭락")],
        ) >= 1
    )
    if direct_field_supply_title and not any(term in text for term in hard_campaign_terms):
        return False
    campaign_hits = count_any(text, campaign_terms)
    if campaign_hits == 0:
        return False
    if any(term in text for term in hard_campaign_terms):
        return True
    strong_public_action = count_any(
        text,
        (
            "농식품부", "정부", "고시", "시행", "공고", "보도자료", "브리핑", "대책",
            "지원사업", "할인지원", "할당관세", "검역", "단속", "수급안정",
        ),
    )
    direct_supply_hits = count_any(text, _QUALITY_DIRECT_SUPPLY_TERMS)
    strong_market_context = (
        has_direct_supply_chain_signal(text)
        or is_dist_market_ops_context(title or "", desc or "")
        or is_dist_field_market_response_context(title or "", desc or "")
    )
    if strong_public_action >= 2 and direct_supply_hits >= 1:
        return False
    if strong_market_context and direct_supply_hits >= 2 and best_horti_score(title or "", desc or "") >= 1.8:
        return False
    title_campaignish = any(term in title_l for term in campaign_terms) or any(term in title_l for term in office_terms)
    agri_partial = count_any(text, ("농업", "농산물", "농가", "원예", "과수", "과일", "채소", "유통", "물류")) >= 1
    return bool(title_campaignish or agri_partial)


def is_low_value_local_promo_context(title: str, desc: str) -> bool:
    """답례품·홍보 판매전·지역 브랜드 알림처럼 수급/유통 실무성이 낮은 기사."""
    text = _nfkc_lower(f"{title or ''} {desc or ''}")
    promo_terms = (
        "고향기부 답례품", "고향사랑 답례품", "답례품", "답례품 인기",
        "홍보 판매전", "홍보판매전", "특별 판매전", "판매전 진행", "기획전",
        "가정의 달", "브랜드 홍보", "소비촉진 홍보", "홍보 행사", "장터 개장",
        "기념행사", "기념 행사", "상생 캠페인", "상생캠페인", "소비 촉진",
        "소비촉진 캠페인",
        "원산지 표시 점검",
    )
    if not any(term in text for term in promo_terms):
        return False
    official_supply_response_hits = count_any(
        text,
        [w.lower() for w in ("농식품부", "농림축산식품부", "정부", "기재부", "한국농수산식품유통공사", "농협")],
    )
    broad_supply_item_hits = count_any(
        text,
        [w.lower() for w in ("농축산물", "농산물", "채소", "과일", "양파", "대파", "수박", "배추", "무")],
    )
    supply_response_hits = count_any(
        text,
        [w.lower() for w in ("수급", "공급 확대", "할인지원", "할인 지원", "가용물량", "비축", "방출", "가격 안정", "물가 안정", "점검", "대비")],
    )
    if official_supply_response_hits >= 1 and broad_supply_item_hits >= 1 and supply_response_hits >= 2:
        return False
    # 가격 급락·산지 폐기 등 시장 distress가 분명한 기사는 소비촉진·할인 문구가 섞여 있어도
    # 지역 판촉 단신이 아니라 수급 실무 기사다. (답례품·상생캠페인·기념행사형 판촉에는
    # 이런 가격 distress 프레이밍이 없으므로 진짜 판촉 분류는 그대로 유지된다.)
    price_distress_hits = count_any(
        text,
        [
            "가격 하락", "가격 급락", "가격 폭락", "값 하락", "값 급락", "값 폭락",
            "가격 약세", "값 약세", "가격 곤두박질", "값 곤두박질", "폭락 우려",
            "급락 우려", "산지 폐기", "공급 과잉", "과잉 생산", "수확기 가격",
        ],
    )
    supply_distress_anchor_hits = count_any(
        text,
        [w.lower() for w in ("농가", "산지", "수급", "출하", "재고", "도매", "유통", "공급", "물량", "판로", "대책")],
    )
    if price_distress_hits >= 1 and supply_distress_anchor_hits >= 1:
        return False
    direct_supply_hits = count_any(text, _QUALITY_DIRECT_SUPPLY_TERMS)
    market_ops = (
        is_dist_market_ops_context(title or "", desc or "")
        or is_dist_sales_channel_ops_context(title or "", desc or "")
        or is_dist_field_market_response_context(title or "", desc or "")
    )
    return not (market_ops and direct_supply_hits >= 2)


def is_wine_lifestyle_noise_context(title: str, desc: str) -> bool:
    """국내 포도 수급이 아닌 와인·주류 라이프스타일 기사를 제외한다."""
    text = _nfkc_lower(f"{title or ''} {desc or ''}")
    wine_terms = ("와인", "wine", "부르고뉴", "보르도", "샤또", "샤토", "소믈리에", "빈티지", "와이너리", "winery", "양조장")
    if not any(term in text for term in wine_terms):
        return False
    domestic_supply_terms = (
        "국산 포도", "국내 포도", "포도 농가", "포도 재배", "포도 출하", "포도 수급",
        "포도 가격", "양조용 포도", "와인포도 재배", "와인 포도 재배",
    )
    if any(term in text for term in domestic_supply_terms):
        return False
    return True


