def is_dist_quality_field_ops_context(title: str, desc: str, dom: str = "", press: str = "") -> bool:
    """도매시장·청과법인·농산물 유통 제도처럼 유통/현장 섹션에 직접 맞는 기사.

    품목 가격 기사나 지역 홍보 단신을 끌어오지 않으면서, 제목에 '농산물'이 없더라도
    도매시장 운영·교육·공간 재배치·출하 실무처럼 유통 현장의 실제 작동과 연결된
    후보를 살리기 위한 품질 신호다.
    """
    ttl = title or ""
    ttl_l = _nfkc_lower(ttl)
    text = _nfkc_lower(f"{ttl} {desc or ''}".strip())
    if not text:
        return False
    compact = re.sub(r"\s+", "", text)
    dom_norm = normalize_host(dom or "")
    press_norm = (press or "").strip()

    if is_remote_foreign_trade_brief_context(ttl, desc or "", dom_norm):
        return False
    if is_wine_lifestyle_noise_context(ttl, desc or ""):
        return False
    if is_low_value_agri_labor_help_context(ttl, desc or ""):
        return False
    if is_low_value_local_promo_context(ttl, desc or ""):
        return False
    if is_dist_political_visit_context(ttl, desc or ""):
        return False
    if is_title_livestock_dominant_context(ttl, desc or ""):
        return False

    primary_supply_title_hits = count_any(ttl_l, [w.lower() for w in _DIST_PRIMARY_SUPPLY_TITLE_TERMS])
    title_quality_anchor_hits = count_any(
        ttl_l,
        [w.lower() for w in (
            "가락시장", "강서시장", "강서 시장", "도매시장", "공판장", "청과",
            "도매법인", "법인협회", "온라인도매시장", "온라인 도매시장",
            "유통 주체", "공간 분리", "유통 혁신", "농산물 유통",
        )],
    )
    if primary_supply_title_hits >= 1 and title_quality_anchor_hits == 0:
        supply_signal_hits = count_any(text, [w.lower() for w in _QUALITY_DIRECT_SUPPLY_TERMS])
        if supply_signal_hits >= 2 and best_horti_score(ttl, desc or "") >= 1.4:
            return False

    hard_title_market = count_any(ttl_l, [w.lower() for w in _DIST_QUALITY_FIELD_MARKET_TERMS])
    hard_title_ops = count_any(ttl_l, [w.lower() for w in _DIST_QUALITY_FIELD_OPS_TERMS])
    if (is_low_value_local_political_context(ttl, desc or "") or is_commodity_political_statement_context(ttl, desc or "")) and (hard_title_market + hard_title_ops) < 2:
        return False

    if (
        is_dist_market_ops_context(ttl, desc or "", dom_norm, press_norm)
        or is_dist_supply_management_center_context(ttl, desc or "")
        or is_dist_sales_channel_ops_context(ttl, desc or "")
        or is_dist_field_market_response_context(ttl, desc or "", dom_norm, press_norm)
        or is_dist_market_disruption_context(ttl, desc or "")
    ):
        return True

    market_hits = count_any(text, [w.lower() for w in _DIST_QUALITY_FIELD_MARKET_TERMS])
    ops_hits = count_any(text, [w.lower() for w in _DIST_QUALITY_FIELD_OPS_TERMS])
    actor_hits = count_any(text, [w.lower() for w in _DIST_QUALITY_FIELD_ACTOR_TERMS])
    agri_hits = count_any(text, [w.lower() for w in _DIST_QUALITY_FIELD_AGRI_TERMS])
    managed_count = int(_managed_commodity_match_summary(ttl, desc or "").get("count") or 0)
    agri_hits += managed_count

    if "강서시장" in compact or "강서 시장" in ttl_l:
        market_hits += 2
    if "법인협회" in text and ("도매" in text or "청과" in text or "온라인도매시장" in compact):
        actor_hits += 1
        market_hits += 1
    if "농산물유통혁신" in compact or "농산물 유통 혁신" in text:
        ops_hits += 2
        agri_hits += 1
    if "물류기자재" in compact or "물류·영농기자재" in text:
        ops_hits += 1
        if "청과" in text or "가락" in text:
            market_hits += 1

    if hard_title_market >= 1 and (hard_title_ops >= 1 or ops_hits >= 2 or actor_hits >= 1) and (agri_hits >= 1 or actor_hits >= 1):
        return True
    if market_hits >= 2 and ops_hits >= 2 and (agri_hits >= 1 or actor_hits >= 1):
        return True
    if actor_hits >= 1 and market_hits >= 1 and ops_hits >= 2:
        return True
    if ("농특위" in text or "농어업농어촌특별위원회" in compact) and ("농산물유통혁신" in compact or ("농산물" in text and "유통 혁신" in text)):
        return True
    if ("강서시장" in compact or "강서 시장" in ttl_l) and ("공간분리" in compact or "유통주체" in compact or "입장차" in text):
        return True
    return False


def is_dist_primary_supply_price_story(title: str, desc: str) -> bool:
    """가격·작황·산지폐기 중심의 수급 기사가 dist 빈칸을 잠식하지 않도록 분리한다."""
    ttl_l = _nfkc_lower(title or "")
    text = _nfkc_lower(f"{title or ''} {desc or ''}".strip())
    if not text:
        return False
    if is_dist_quality_field_ops_context(title, desc):
        return False
    title_supply_hits = count_any(ttl_l, [w.lower() for w in _DIST_PRIMARY_SUPPLY_TITLE_TERMS])
    if title_supply_hits == 0:
        return False
    dist_ops_hits = count_any(text, [w.lower() for w in _DIST_QUALITY_FIELD_OPS_TERMS])
    if dist_ops_hits >= 2:
        return False
    return has_direct_supply_chain_signal(text) or best_horti_score(title or "", desc or "") >= 1.4



def is_blocked_domain(dom: str) -> bool:
    if not dom:
        return False
    dom = dom.lower()
    if dom in BLOCKED_DOMAINS:
        return True
    for b in BLOCKED_DOMAINS:
        if dom.endswith("." + b):
            return True
    return False

def agri_strength_score(text: str) -> int:
    return count_any(text, AGRI_STRONG_TERMS)


def _section_must_terms_lower(section_conf: JsonDict) -> list[str]:
    """Return cached lower-cased must_terms for a section config."""
    if not isinstance(section_conf, dict):
        return []
    cached = section_conf.get("_must_terms_lower")
    if isinstance(cached, list):
        return cached
    out = [str(t).lower() for t in (section_conf.get("must_terms") or []) if str(t).strip()]
    # lightweight cache on in-memory config dict
    section_conf["_must_terms_lower"] = out
    return out


def keyword_strength(text: str, section_conf: JsonDict) -> int:
    """섹션 관련 키워드 강도(정수).
    - 섹션 must_terms 포함 여부(1차) + 농산물 강키워드(AGRI_STRONG_TERMS) 기반 점수
    - dist/pest에서 낚시성 기사 제거에 사용
    """
    if not section_conf:
        return agri_strength_score(text)
    must = _section_must_terms_lower(section_conf)
    return count_any(text, must) + agri_strength_score(text)

# 2026-04-11: section_fit_score 결과 캐싱 (process-lifetime 메모이제이션)
# 동일한 (title, desc, section_key, dom, press) 입력은 항상 동일한 출력을
# 반환하는 pure function 이므로, daily run 1회당 수천 번 반복 호출되는
# section_fit_score 를 LRU 캐시로 가속.
# 예상 hit rate: 80%+ (select_top_articles sort + audit + reassign 반복 호출)
# 메모리 사용: ~500 unique articles × 4 sections × 16 bytes = ~32 KB
# 품질 영향 없음 (결정적 함수, 동일 입력 → 동일 출력 보장)
_SECTION_FIT_SCORE_CACHE: dict[tuple[str, str, str, str, str], float] = {}


def _is_supply_climate_output_context(title: str, desc: str) -> bool:
    title_l = _nfkc_lower(title or "")
    desc_l = _nfkc_lower(desc or "")
    text_l = _nfkc_lower(f"{title or ''} {desc or ''}")
    managed = int(_managed_commodity_match_summary(title or "", desc or "").get("count") or 0) >= 1
    climate = any(term in title_l for term in ("폭염", "고온", "장마", "기후변화"))
    output = any(term in desc_l for term in ("생산량", "출하량", "수급 불안", "수급안정", "수급 안정"))
    measured = bool(
        re.search(r"\d+(?:\.\d+)?\s*%", text_l)
        or re.search(r"(?:최대\s*)?\d+(?:\.\d+)?\s*배", text_l)
    )
    return bool(managed and climate and output and measured)


def _is_dist_export_growth_context(title: str, desc: str) -> bool:
    title_l = _nfkc_lower(title or "")
    text_l = _nfkc_lower(f"{title or ''} {desc or ''}")
    commodity = int(_managed_commodity_match_summary(title or "", desc or "").get("count") or 0) >= 1
    export_title = any(
        term in title_l
        for term in (
            "수출 증가", "수출량 증가", "수출 확대", "수출량 확대",
            "수출 쑥쑥", "수출 ‘쑥쑥’", "수출 '쑥쑥'", "수출 성장",
        )
    )
    measured = bool(
        len(re.findall(r"\d+(?:\.\d+)?\s*톤", text_l)) >= 2
        or re.search(r"\d+(?:\.\d+)?\s*배", text_l)
        or re.search(r"\d+(?:\.\d+)?\s*%", text_l)
    )
    return bool(commodity and export_title and measured)


def _is_dist_apc_automation_context(title: str, desc: str) -> bool:
    title_l = _nfkc_lower(title or "")
    text_l = _nfkc_lower(f"{title or ''} {desc or ''}")
    crop_ops = any(term in title_l for term in ("선별", "포장")) and any(
        term in title_l for term in ("로봇", "자동화")
    )
    apc = any(term in text_l for term in ("apc", "산지유통센터", "스마트 농산물산지유통센터"))
    commodity = int(_managed_commodity_match_summary(title or "", desc or "").get("count") or 0) >= 1
    installed_or_operating = any(
        term in text_l for term in ("전국 최초", "시스템을 갖춘", "자동화 시스템", "운영", "가동")
    )
    demo_only = any(term in text_l for term in ("시연 행사", "장비 시연", "기술을 선보였다")) and not installed_or_operating
    return bool(crop_ops and apc and commodity and installed_or_operating and not demo_only)


def section_fit_score(title: str, desc: str, section_conf: JsonDict, dom: str = "", press: str = "") -> float:
    """해당 기사가 섹션 의도와 얼마나 맞는지(0+).
    - must_terms 텍스트 히트 + 제목 히트(가중)
    - 원예 핵심 신호를 약하게 추가해 완전 비관련 기사 상단 배치를 줄임
    """
    # 캐시 체크: 동일 입력이면 즉시 반환
    _sec_key = str(section_conf.get("key")) if isinstance(section_conf, dict) else ""
    _cache_key = (title or "", desc or "", _sec_key, dom or "", press or "")
    _cached = _SECTION_FIT_SCORE_CACHE.get(_cache_key)
    if _cached is not None:
        return _cached

    txt = f"{title or ''} {desc or ''}".lower()
    ttl = (title or "").lower()
    must = _section_must_terms_lower(section_conf) if section_conf else []
    must_t = count_any(txt, must) if must else 0
    must_h = count_any(ttl, must) if must else 0
    base = (0.18 * must_t) + (0.40 * must_h)
    # 완전 무관 기사 방어용 약한 보정
    base += 0.10 * min(6, agri_strength_score(txt))
    key = str(section_conf.get("key")) if isinstance(section_conf, dict) else ""
    broad_macro_price = is_broad_macro_price_context(title, desc)
    policy_stabilization = is_supply_stabilization_policy_context(txt, dom, press)
    policy_market_brief = is_policy_market_brief_context(txt, dom, press)
    policy_major_issue = is_policy_major_issue_context(title, desc, dom, press)
    policy_legislative_reform = is_policy_legislative_reform_context(title, desc, dom, press)
    managed_summary = _managed_commodity_match_summary(title, desc)
    managed_count = int(managed_summary.get("count") or 0)
    program_core_count = int(managed_summary.get("program_core_count") or 0)
    dist_supply_center = is_dist_supply_management_center_context(title, desc)
    dist_sales_channel_ops = is_dist_sales_channel_ops_context(title, desc)
    dist_field_market_response = is_dist_field_market_response_context(title, desc, dom, press)
    dist_quality_field_ops = is_dist_quality_field_ops_context(title, desc, dom, press)
    dist_diversity_bucket = dist_operational_diversity_bucket(title, desc, dom, press) if key == "dist" else ""
    dist_national_export_logistics = is_dist_national_export_logistics_context(title, desc, dom, press) if key == "dist" else False
    supply_price_collapse_field = is_supply_price_collapse_field_context(title, desc, dom, press)
    dist_apc_nh_core = is_dist_apc_nh_core_context(title, desc)
    dist_low_value_donation = is_dist_low_value_donation_context(title, desc)
    pest_fire_blight_risk = is_pest_fire_blight_farmer_risk_context(title, desc)
    dist_anchor_hits = count_any(
        txt,
        [t.lower() for t in ("가락시장", "도매시장", "공판장", "경락", "경매", "반입", "산지유통", "산지유통센터", "온라인 도매시장")],
    )
    macro_policy = is_macro_policy_issue(txt)
    policy_export_support = is_policy_export_support_brief_context(title, desc)
    if key in ("supply", "policy", "dist"):
        if is_commodity_corporate_stock_context(title, desc):
            base -= 4.0
        if is_non_agri_auto_market_context(title, desc):
            base -= 3.8
        if is_non_agri_ai_robot_industry_context(title, desc):
            base -= 3.8
        if key == "supply" and is_supply_unmanaged_broad_price_roundup_context(title, desc):
            base -= 3.2
        if key == "supply":
            supply_fit_text = _nfkc_lower(f"{title or ''} {desc or ''}")
            if count_any(_nfkc_lower(title or ""), [w.lower() for w in ("로컬푸드 이야기", "발효와 가공", "시간을 파는 기술")]) >= 1:
                base -= 2.8
            if (
                count_any(supply_fit_text, [w.lower() for w in ("양액 냉각기", "수경재배 냉각", "장비 점검")]) >= 1
                and not _is_supply_climate_output_context(title, desc)
            ):
                base -= 2.4
            if _is_supply_climate_output_context(title, desc):
                base += 2.6
        if is_wine_lifestyle_noise_context(title, desc):
            base -= 3.4
        if is_low_value_local_political_context(title, desc) and not (
            key == "dist" and _is_dist_apc_automation_context(title, desc)
        ):
            base -= 2.6
        if is_low_value_agri_labor_help_context(title, desc):
            base -= 3.0 if key == "supply" else 1.8
        if is_low_value_local_promo_context(title, desc) and not (
            key == "dist" and _is_dist_apc_automation_context(title, desc)
        ):
            base -= 2.2 if key in ("supply", "dist") else 1.2
    if key == "policy":
        if is_non_agri_transport_policy_context(title, desc):
            base -= 3.2
        if is_title_livestock_dominant_context(title, desc):
            base -= 1.4
        if is_policy_forest_admin_noise_context(title, desc):
            base -= 1.2
        if is_policy_budget_drive_noise_context(title, desc):
            base -= 1.1
        if macro_policy:
            base += 0.9
            if broad_macro_price:
                base += 0.6
            if policy_stabilization:
                base += 0.85
            if policy_market_brief:
                base += 0.95
        if policy_major_issue:
            base += 1.05
        if policy_legislative_reform:
            base += 1.45
        if policy_export_support:
            base += 0.85
        if (
            any(term in _nfkc_lower(title or "") for term in ("정부비축 국산 콩", "비축 국산 콩", "국산 콩"))
            and any(term in _nfkc_lower(f"{title or ''} {desc or ''}") for term in ("6만5000톤", "65000톤", "비축", "방출", "공급"))
        ):
            base += 1.85
        if (
            "농산물" in txt
            and "도매시장" in txt
            and "출하예측" in txt
            and ("20개 품목" in txt or "20개품목" in txt)
        ):
            base += 2.65
        if is_dist_export_field_context(title, desc):
            base -= 0.9
        if dist_field_market_response:
            base -= 0.85
        if managed_count and (macro_policy or policy_stabilization or policy_market_brief or policy_major_issue or policy_export_support):
            base += min(0.56, 0.12 * managed_count)
            base += min(0.36, 0.16 * program_core_count)
    elif key == "dist":
        if _is_dist_export_growth_context(title, desc):
            base += 2.4
        if _is_dist_apc_automation_context(title, desc):
            base += 2.8
        if is_dist_political_visit_context(title, desc):
            base -= 1.4
        if is_local_agri_infra_designation_context(title, desc):
            base -= 1.1
        if is_dist_local_crop_strategy_noise_context(title, desc):
            base -= 1.2
        if dist_low_value_donation:
            base -= 1.6
        if is_dist_export_shipping_context(title, desc):
            base += 1.15
        if is_dist_export_field_context(title, desc):
            base += 1.05
        if is_dist_export_support_hub_context(title, desc):
            base += 1.0
        if dist_national_export_logistics:
            base += 1.45
        if dist_supply_center:
            base += 1.1
        if dist_sales_channel_ops:
            base += 1.15
        if dist_field_market_response:
            base += 1.25
        if dist_quality_field_ops:
            base += 1.35
        if dist_diversity_bucket == "apc_nh":
            base += 1.25 if dist_apc_nh_core else 0.45
        elif dist_diversity_bucket == "export":
            base += 0.35
        dist_disruption_scope = dist_market_disruption_scope(title, desc)
        if dist_disruption_scope == "systemic":
            base += 1.9
        elif dist_disruption_scope == "market_disruption":
            base += 1.25
        elif dist_disruption_scope == "commodity_aftershock":
            base += 0.65
        if is_local_agri_org_feature_context(title, desc):
            if is_dist_local_field_profile_context(title, desc):
                base += 0.55
            elif is_dist_local_org_tail_context(title, desc):
                base -= 0.9
            else:
                base += 0.25
        if managed_count and (dist_anchor_hits >= 1 or is_dist_export_shipping_context(title, desc) or is_dist_export_field_context(title, desc) or dist_field_market_response):
            base += min(0.52, 0.12 * managed_count)
            base += min(0.32, 0.14 * program_core_count)
    elif key == "supply":
        feature_kind = supply_feature_context_kind(title, desc)
        if is_supply_social_policy_noise_context(title, desc):
            base -= 2.4
        if is_supply_price_outlook_context(title, desc):
            base += 0.78
        if supply_price_collapse_field:
            base += 1.45
            if (press or "").strip() in {"KBS", "MBC", "SBS"}:
                base += 0.45
        if (
            "농산물" in txt
            and any(term in txt for term in ("출하 몰려", "출하량", "반입", "물량"))
            and any(term in txt for term in ("가격 급락", "가격 하락", "값 급락", "값 하락", "급락"))
            and any(term in txt for term in ("늦은장마", "늦은 장마", "장마", "무더위", "폭염"))
        ):
            base += 3.0
        if _is_supply_climate_output_context(title, desc):
            base += 1.8
        if is_title_livestock_dominant_context(title, desc):
            base -= 1.3
        # 인물/르포/하이라이트 시리즈는 수급 기사가 아니므로 큰 감점
        if _is_profile_feature_story(title, desc):
            base -= 2.0
        if feature_kind == "field":
            base += 0.55
        elif feature_kind == "quality":
            base += 0.45
        elif feature_kind == "promo":
            base += 0.38
        if is_local_agri_org_feature_context(title, desc):
            base -= 1.0
        # 컨설팅/기술지도/교육: 지자체 행정이지 수급 기사가 아님
        if is_agri_training_recruitment_context(title, desc):
            base -= 1.8
        if _is_admin_consulting_story(title, desc):
            base -= 2.0
        if is_dist_export_shipping_context(title, desc):
            base -= 1.45
        if dist_supply_center:
            base -= 0.95
        if dist_sales_channel_ops:
            base -= 1.15
        if dist_field_market_response:
            base -= 1.15
        if is_supply_weak_tail_context(title, desc):
            base -= 1.1
        if policy_stabilization:
            base -= 1.1
        if policy_market_brief:
            base -= 1.35
        if broad_macro_price and ((not has_direct_supply_chain_signal(txt)) or policy_market_brief):
            base -= 1.0
        if is_macro_policy_issue(txt) and count_any((title or "").lower(), [t.lower() for t in ("과일", "과수", "채소", "화훼", "농산물", "청과")]) == 0 and best_horti_score(title or "", "") < 1.6 and best_horti_score(title or "", desc or "") < 1.8 and ((not has_direct_supply_chain_signal(txt)) or policy_market_brief):
            base -= 0.6
        # 유가/에너지 primary 기사: 품목 수급과 무관하므로 큰 감점
        if is_oil_energy_primary_macro_context(title, desc):
            base -= 4.0
        # 해외 축산(중국 돼지고기 등): 국내 원예 수급과 무관
        if _is_overseas_livestock_story(title, desc):
            base -= 4.0
        # 로컬 브랜딩/스포츠 이벤트: 수급과 무관
        if _is_local_branding_event_story(title, desc):
            base -= 3.0
        if managed_count:
            base += min(0.72, 0.15 * managed_count)
            base += min(0.48, 0.22 * program_core_count)
        # 시장 인프라 기사 (가락시장 출하비용 보전 등)는 supply에서도 유효
        _supply_market_infra = ("가락시장", "도매시장", "공판장", "출하비용", "보전사업")
        _smi_hits = count_any(txt, [t.lower() for t in _supply_market_infra])
        if _smi_hits >= 2:
            base += 0.85
        elif _smi_hits >= 1:
            base += 0.45
    elif key == "pest":
        if is_pest_input_marketing_noise_context(title, desc):
            base -= 1.3
        if is_pest_story_focus_strong(title, desc):
            base += 0.75
        if pest_fire_blight_risk:
            base += 1.25
        if is_pest_control_policy_context(txt):
            base += 0.55
        if is_pest_official_photo_check_context(title, desc, dom, press):
            base -= 0.35
        if any(w in txt for w in ("냉해", "동해", "서리", "저온", "병해충", "방제")):
            base += 0.35
        if managed_count:
            base += min(0.50, 0.12 * managed_count)
            base += min(0.32, 0.16 * program_core_count)
    _result = round(base, 3)
    _SECTION_FIT_SCORE_CACHE[_cache_key] = _result
    return _result

def off_topic_penalty(text: str) -> int:
    return count_any(text, OFFTOPIC_HINTS)

def korea_context_score(text: str) -> int:
    return count_any(text, KOREA_CONTEXT_HINTS)

def global_retail_protest_penalty(text: str) -> int:
    return count_any(text.lower(), GLOBAL_RETAIL_PROTEST_HINTS)

# -----------------------------
# Section signal weights (원예수급 핵심성 가중치)
# - '키워드 강도'를 단순 카운트가 아니라 가중치 합으로 반영
# -----------------------------
def weighted_hits(text: str, weight_map: dict[str, float]) -> float:
    return sum(w for k, w in weight_map.items() if k in text)

